    home_mianheading5 = "Delta \u043E\u0442\u043A\u0440\u044B\u043B\u0430 \u043D\u043E\u0432\u0443\u044E \u044D\u0440\u0443 \u0434\u0435\u0446\u0435\u043D\u0442\u0440\u0430\u043B\u0438\u0437\u043E\u0432\u0430\u043D\u043D\u044B\u0445 \u0446\u0438\u0444\u0440\u043E\u0432\u044B\u0445 \u0434\u0435\u043D\u0435\u0433 \u0434\u043B\u044F \u0432\u0441\u0435\u0433\u043E \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u0442\u0432\u0430, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043D\u0435 \u0442\u0440\u0435\u0431\u0443\u044E\u0442 \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u043F\u0440\u0438\u0432\u0430\u0442\u043D\u043E\u0433\u043E \u043A\u043B\u044E\u0447\u0430!";
    home_subheading4 = "\u0412\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u043D\u0430\u0447\u0430\u0442\u044C \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u043C\u043E\u0431\u0438\u043B\u044C\u043D\u043E\u0435 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0435 Delta \u0443\u0436\u0435 \u0441\u0435\u0439\u0447\u0430\u0441, \u0447\u0442\u043E\u0431\u044B \u0434\u043E\u0431\u044B\u0432\u0430\u0442\u044C \u0446\u0438\u0444\u0440\u043E\u0432\u044B\u0435 \u0434\u0435\u043D\u044C\u0433\u0438 \u0414\u0435\u043B\u044C\u0442\u0430 \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u043E \u0438 \u0441 \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u0435\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438, \u0430 \u0442\u0430\u043A\u0436\u0435 \u043B\u0435\u0433\u043A\u043E \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0442\u044C \u043C\u0435\u0436\u0446\u0435\u043F\u043E\u0447\u0435\u0447\u043D\u044B\u043C\u0438 \u0430\u043A\u0442\u0438\u0432\u0430\u043C\u0438...";
    no_private_key4 = "\u041D\u0435\u0442 \u0437\u0430\u043A\u0440\u044B\u0442\u043E\u0433\u043E \u043A\u043B\u044E\u0447\u0430";
    no_mnemonic_words4 = "\u041D\u0435\u0442 \u043C\u043D\u0435\u043C\u043E\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0441\u043B\u043E\u0432";
    no_password4 = "\u041D\u0435\u0442 \u043F\u0430\u0440\u043E\u043B\u044F";
    download_delta_application_now5 = "\u0417\u0430\u0433\u0440\u0443\u0437\u0438\u0442\u0435 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0435 Delta \u043F\u0440\u044F\u043C\u043E \u0441\u0435\u0439\u0447\u0430\u0441";
    explore5 = "\u041F\u043E\u0441\u0435\u0442\u0438\u0442\u0435 \u0441\u0430\u0439\u0442";
    learn_more5 = "\u0443\u0437\u043D\u0430\u0442\u044C \u0431\u043E\u043B\u044C\u0448\u0435";
    download_heading5 = "\u0417\u0430\u0433\u0440\u0443\u0437\u0438\u0442\u0435 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0435 Delta \u0438 \u043D\u0430\u0447\u043D\u0438\u0442\u0435 \u0434\u043E\u0431\u044B\u0432\u0430\u0442\u044C \u0438 \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0442\u044C \u0430\u043A\u0442\u0438\u0432\u0430\u043C\u0438..., \u041F\u0440\u0438\u0441\u043E\u0435\u0434\u0438\u043D\u044F\u0439\u0442\u0435\u0441\u044C \u043F\u0440\u044F\u043C\u043E \u0441\u0435\u0439\u0447\u0430\u0441!";
    download_desc14 = "\u041D\u0435 \u043D\u0443\u0436\u043D\u043E \u0432\u043A\u043B\u0430\u0434\u044B\u0432\u0430\u0442\u044C \u043D\u0438 \u0446\u0435\u043D\u0442\u0430 \u043B\u0435\u0433\u0430\u043B\u044C\u043D\u043E\u0439 \u0432\u0430\u043B\u044E\u0442\u044B! Delta - \u044D\u0442\u043E \u0432\u0430\u0448\u0438 \u0434\u0435\u043D\u044C\u0433\u0438, \u0432\u044B \u0438\u043C\u0435\u0435\u0442\u0435 \u043F\u0440\u0430\u0432\u043E \u0434\u043E\u0431\u044B\u0432\u0430\u0442\u044C \u0438\u0445 \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u043E, \u0432\u0441\u0435, \u0447\u0442\u043E \u0432\u0430\u043C \u043D\u0443\u0436\u043D\u043E, - \u044D\u0442\u043E \u043D\u0430\u0434\u0435\u0436\u043D\u044B\u0439 <u>\u0440\u0435\u0444\u0435\u0440\u0430\u043B\u044C\u043D\u044B\u0439 DID</u>.";
    is_no_referrer_DID_yet4 = "\u0415\u0441\u043B\u0438 \u0435\u0449\u0435 \u043D\u0435\u0442 \u0440\u0435\u0444\u0435\u0440\u0435\u0440\u0430 DID";
    search_find_delta_referrer3 = "\u0412\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u043D\u0430\u0439\u0442\u0438 Delta referrer DID \u0447\u0435\u0440\u0435\u0437 \u043F\u043E\u0438\u0441\u043A \u0432 \u0418\u043D\u0442\u0435\u0440\u043D\u0435\u0442\u0435";
    download_desc24 = "\u0415\u0441\u043B\u0438 \u0443 \u0432\u0430\u0441 \u0443\u0436\u0435 \u0435\u0441\u0442\u044C \u0440\u0435\u0444\u0435\u0440\u0435\u0440 DID, \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u043D\u0430\u0436\u0430\u0442\u044C \u043D\u0430 \u0438\u043A\u043E\u043D\u043A\u0443 \u043D\u0438\u0436\u0435, \u0447\u0442\u043E\u0431\u044B \u0437\u0430\u0433\u0440\u0443\u0437\u0438\u0442\u044C \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0435 Delta.";
    decentralization5 = "\u0414\u0435\u0446\u0435\u043D\u0442\u0440\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044F";
    decentralization_desc4 = "\u0411\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E, \u0441 \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u043C \u0438\u0441\u0445\u043E\u0434\u043D\u044B\u043C \u043A\u043E\u0434\u043E\u043C, \u043F\u0440\u043E\u0437\u0440\u0430\u0447\u043D\u043E, \u043D\u0435\u0438\u0437\u043C\u0435\u043D\u044F\u0435\u043C\u043E, \u0438 \u0432\u0441\u0435 \u0443\u0447\u0430\u0441\u0442\u0432\u0443\u044E\u0442 \u0432 \u043A\u0430\u0441\u0442\u0438\u043D\u0433\u0435 \u0438 \u0441\u0435\u0440\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438";
    mobile_first5 = "\u041C\u043E\u0431\u0438\u043B\u044C\u043D\u0430\u044F \u0441\u0432\u044F\u0437\u044C \u043F\u0440\u0435\u0432\u044B\u0448\u0435 \u0432\u0441\u0435\u0433\u043E";
    mobile_first_desc4 = "\u041F\u0440\u043E\u0441\u0442\u043E\u0439 \u0432 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u0438, \u0434\u043E\u0431\u044B\u0432\u0430\u0439\u0442\u0435 \u0438 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 \u0444\u0443\u043D\u043A\u0446\u0438\u0438 \u043D\u0430 \u0441\u0432\u043E\u0435\u043C \u043C\u043E\u0431\u0438\u043B\u044C\u043D\u043E\u043C \u0442\u0435\u043B\u0435\u0444\u043E\u043D\u0435";
    environment_friendly5 = "\u042D\u043A\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438 \u0447\u0438\u0441\u0442\u044B\u0439";
    environment_friendly_desc3 = "\u041E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u0434\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u043F\u043E\u0442\u0440\u0435\u0431\u043B\u0435\u043D\u0438\u044F \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u044D\u043D\u0435\u0440\u0433\u0438\u0438 \u0438 \u0441\u0435\u0442\u0438, \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u0431\u043E\u043B\u044C\u0448\u043E\u0433\u043E \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u0430 \u044D\u043B\u0435\u043A\u0442\u0440\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u043E\u0442\u0445\u043E\u0434\u043E\u0432";
    safety_circle4 = "\u041A\u0440\u0443\u0433 \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u0438";
    safety_circle_desc4 = "\u0421\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u0430\u044F \u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0430 \u0434\u0432\u043E\u0439\u043D\u043E\u0439 \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u0438, \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u0435 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438 \u043D\u0435 \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u043E\u0442 \u043A\u0430\u043A\u043E\u0439-\u043B\u0438\u0431\u043E \u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u043E\u0439 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0438";
    fair_distribution5 = "\u0441\u043F\u0440\u0430\u0432\u0435\u0434\u043B\u0438\u0432\u043E\u0435 \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u0438\u0435";
    fair_distribution_desc5 = "\u041C\u0435\u0442\u043E\u0434 \u0432\u044B\u043F\u0443\u0441\u043A\u0430 \u2014 \u0447\u0435\u0440\u0435\u0437 \u0432\u043E\u0437\u043D\u0430\u0433\u0440\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u0437\u0430 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u043C\u0430\u0439\u043D\u0438\u043D\u0433 \u0438 \u044D\u043A\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0441\u0442\u0440\u043E\u0438\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u043E, \u0431\u0435\u0437 \u043A\u0430\u043A\u043E\u0439-\u043B\u0438\u0431\u043E \u043F\u0440\u0435\u0434\u0432\u0430\u0440\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0439 \u043F\u0440\u043E\u0434\u0430\u0436\u0438 \u0438 ICO.";
    web3_application_center5 = "\u0426\u0435\u043D\u0442\u0440 Web3 <u title='\u041F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0435'>App</u>";
    web3_application_center_desc5 = "\u041B\u0435\u0433\u043A\u043E \u0441\u043E\u0437\u0434\u0430\u0432\u0430\u0442\u044C \u0438 \u043F\u0443\u0431\u043B\u0438\u043A\u043E\u0432\u0430\u0442\u044C \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u044F Web3 \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E dApp Application Plaza";
    ICP_smart_blockchain5 = "\u0418\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0443\u0430\u043B\u044C\u043D\u044B\u0439 \u0431\u043B\u043E\u043A\u0447\u0435\u0439\u043D ICP";
    ICP_smart_blockchain_desc3 = "\u041E\u043F\u0435\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u0430\u044F \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u0430 \u043D\u0430 \u043E\u0441\u043D\u043E\u0432\u0435 \u0441\u043C\u0430\u0440\u0442-\u043A\u043E\u043D\u0442\u0440\u0430\u043A\u0442\u043E\u0432 ICP, \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u044B\u0435, \u043D\u0430\u0434\u0435\u0436\u043D\u044B\u0435, \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u044B\u0435 \u0432\u044B\u0447\u0438\u0441\u043B\u0435\u043D\u0438\u044F, \u043D\u0435\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435";
    DAO_governance_model3 = "\u041C\u043E\u0434\u0435\u043B\u044C DAO <u title='\u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435'>gov</u>";
    DAO_governance_model_desc3 = "\u0414\u0435\u0446\u0435\u043D\u0442\u0440\u0430\u043B\u0438\u0437\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u0441\u043E\u0432\u043C\u0435\u0441\u0442\u043D\u043E\u0435 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0434\u043B\u044F \u0432\u0441\u0435\u0433\u043E \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u0442\u0432\u0430, \u0441\u0431\u0430\u043B\u0430\u043D\u0441\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435, \u0434\u043E\u043B\u0433\u043E\u0441\u0440\u043E\u0447\u043D\u0430\u044F \u043D\u0430\u0434\u0435\u0436\u043D\u043E\u0441\u0442\u044C";
    explore_delta_heading3 = "    \u041E\u0442\u043A\u0440\u043E\u0439\u0442\u0435 \u0434\u043B\u044F \u0441\u0435\u0431\u044F \u0442\u0430\u0439\u043D\u0443 Delta, <br/> \u0414\u0430\u0432\u0430\u0439\u0442\u0435 \u0432\u043C\u0435\u0441\u0442\u0435 \u043F\u043E\u0441\u0442\u0440\u043E\u0438\u043C \u043F\u043E\u043B\u043D\u0443\u044E \u044D\u043A\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u0446\u0435\u043F\u043E\u0447\u043A\u0443 \u0431\u0443\u0434\u0443\u0449\u0435\u0439 \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0439 \u0446\u0438\u0444\u0440\u043E\u0432\u043E\u0439 \u0432\u0430\u043B\u044E\u0442\u044B...";
    access_terminal5 = "\u0422\u0435\u0440\u043C\u0438\u043D\u0430\u043B \u0434\u043E\u0441\u0442\u0443\u043F\u0430";
    DSMS_access_terminal_heading4 = `\u0422\u0435\u0440\u043C\u0438\u043D\u0430\u043B \u0434\u043E\u0441\u0442\u0443\u043F\u0430 <span style='font-size: large'>DSMS \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438</span> - \u044D\u0442\u043E \u0434\u0435\u0446\u0435\u043D\u0442\u0440\u0430\u043B\u0438\u0437\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u0442\u0435\u0440\u043C\u0438\u043D\u0430\u043B \u0434\u043E\u0441\u0442\u0443\u043F\u0430 Delta \u043A SMS \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0444\u0440\u043E\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0439 \u0447\u0430\u0441\u0442\u044C\u044E \u0440\u0435\u0448\u0435\u043D\u0438\u044F "\u0442\u0440\u0438 \u0431\u0435\u0437 \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438" (\u043D\u0435\u0442 \u0437\u0430\u043A\u0440\u044B\u0442\u043E\u0433\u043E \u043A\u043B\u044E\u0447\u0430, \u043D\u0435\u0442 \u043C\u043D\u0435\u043C\u043E\u043D\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0444\u0440\u0430\u0437\u044B, \u043D\u0435 \u0442\u0440\u0435\u0431\u0443\u0435\u0442\u0441\u044F \u043F\u0430\u0440\u043E\u043B\u044C).`;
    access_terminal_question14 = "\u041A\u0430\u043A\u0438\u0435 \u043F\u0440\u0435\u0438\u043C\u0443\u0449\u0435\u0441\u0442\u0432\u0430 \u0434\u0430\u0435\u0442 \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u0435 \u0441\u0442\u0430\u0442\u0443\u0441\u0430 \u0432\u0430\u043B\u0438\u0434\u0430\u0442\u043E\u0440\u0430?";
    access_terminal_question24 = "\u041A\u0430\u043A \u0441\u0442\u0430\u0442\u044C \u0432\u0430\u043B\u0438\u0434\u0430\u0442\u043E\u0440\u043E\u043C?";
    access_terminal_question34 = "\u041D\u0443\u0436\u043D\u043E \u043B\u0438 \u0437\u0430\u0433\u0440\u0443\u0436\u0430\u0442\u044C \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u0443 \u0442\u0435\u0440\u043C\u0438\u043D\u0430\u043B\u0430?";
    access_terminal_question44 = "\u0427\u0442\u043E \u043D\u0443\u0436\u043D\u043E \u043F\u043E\u0434\u0433\u043E\u0442\u043E\u0432\u0438\u0442\u044C \u0432\u0430\u043B\u0438\u0434\u0430\u0442\u043E\u0440\u0443?";
    access_terminal_answer14 = "\u0412 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u0432\u0430\u043B\u0438\u0434\u0430\u0442\u043E\u0440\u044B \u0441\u043E\u0432\u043C\u0435\u0441\u0442\u043D\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442 \u0440\u0435\u0441\u0443\u0440\u0441\u044B \u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0438 \u0434\u043B\u044F \u043E\u0431\u0435\u0441\u043F\u0435\u0447\u0435\u043D\u0438\u044F \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u0438 \u0441\u0435\u0442\u0438 Delta, \u043E\u043D\u0438 \u0442\u0430\u043A\u0436\u0435 \u043C\u043E\u0433\u0443\u0442 \u043F\u043E\u043B\u0443\u0447\u0430\u0442\u044C \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435 \u0432\u043E\u0437\u043D\u0430\u0433\u0440\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0437\u0430 \u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0443. \u041F\u043E\u0434\u0440\u043E\u0431\u043D\u0435\u0435 \u043E \u043F\u0440\u0430\u0432\u0438\u043B\u0430\u0445 \u0432\u043E\u0437\u043D\u0430\u0433\u0440\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0432\u0430\u043B\u0438\u0434\u0430\u0442\u043E\u0440\u043E\u0432 \u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u0440\u0430\u0437\u0434\u0435\u043B\u0430\u0445 \u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u0430\u0446\u0438\u0438.";
    access_terminal_answer24 = '\u0423 \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0435\u0441\u0442\u044C \u0448\u0430\u043D\u0441 \u0441\u0442\u0430\u0442\u044C \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0442\u043E\u0440\u043E\u043C. \u0415\u0441\u043B\u0438 \u0432\u044B \u0445\u043E\u0442\u0438\u0442\u0435 \u0441\u0442\u0430\u0442\u044C \u0443\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u043E\u043C \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438, \u0437\u0430\u0439\u0434\u0438\u0442\u0435 \u043D\u0430 \u0441\u0442\u0440\u0430\u043D\u0438\u0446\u0443 "\u041C\u0435\u043D\u044E" \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u044F Delta App \u0438 \u043D\u0430\u0439\u0434\u0438\u0442\u0435 \u0437\u0430\u043F\u0438\u0441\u044C "DSMS Verification Qualification". \u041F\u043E\u0441\u043B\u0435 \u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0438 \u0438 \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u0443\u0441\u043B\u043E\u0432\u0438\u0439 \u0432\u044B \u0441\u043C\u043E\u0436\u0435\u0442\u0435 \u0441\u0442\u0430\u0442\u044C \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0442\u043E\u0440\u043E\u043C.';
    access_terminal_answer34 = "\u041F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044F\u043C Delta, \u043D\u0435 \u043F\u043E\u043B\u0443\u0447\u0438\u0432\u0448\u0438\u043C \u043A\u0432\u0430\u043B\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044E \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0442\u043E\u0440\u0430, \u043D\u0435 \u043D\u0443\u0436\u043D\u043E \u0437\u0430\u0433\u0440\u0443\u0436\u0430\u0442\u044C \u0442\u0435\u0440\u043C\u0438\u043D\u0430\u043B \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438.";
    access_terminal_answer44 = "\u0415\u0441\u043B\u0438 \u0432\u044B \u043F\u043E\u043B\u0443\u0447\u0438\u043B\u0438 \u043A\u0432\u0430\u043B\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044E \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0442\u043E\u0440\u0430, \u0432\u0430\u043C \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u043F\u043E\u0434\u0433\u043E\u0442\u043E\u0432\u0438\u0442\u044C \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0439 \u0441\u043C\u0430\u0440\u0442\u0444\u043E\u043D \u0438 \u0432\u044B\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0439 <span class='underline' title='\u043E\u0431\u044B\u0447\u043D\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u0439 \u043A\u0430\u043A: \u043D\u043E\u043C\u0435\u0440 \u043C\u043E\u0431\u0438\u043B\u044C\u043D\u043E\u0433\u043E \u0442\u0435\u043B\u0435\u0444\u043E\u043D\u0430'>MSISDN</span>, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0438\u043C\u0435\u0442\u044C \u0445\u043E\u0440\u043E\u0448\u0438\u0439 \u0441\u0438\u0433\u043D\u0430\u043B. \u0423\u0441\u043B\u043E\u0432\u0438\u044F \u0434\u043B\u044F \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0438 \u0442\u0435\u0440\u043C\u0438\u043D\u0430\u043B\u043E\u0432 \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438 \u0438 \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F \u0437\u0430\u0434\u0430\u0447 \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u0433\u043E \u0434\u043E\u0441\u0442\u0443\u043F\u0430 \u0432 \u0440\u0435\u0436\u0438\u043C\u0435 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438.";
