    download_desc16 = "\u0915\u093E\u0928\u0942\u0928\u0940 \u092E\u0941\u0926\u094D\u0930\u093E \u0915\u093E 1 \u092A\u094D\u0930\u0924\u093F\u0936\u0924 \u092D\u0940 \u0928\u093F\u0935\u0947\u0936 \u0915\u0930\u0928\u0947 \u0915\u0940 \u0906\u0935\u0936\u094D\u092F\u0915\u0924\u093E \u0928\u0939\u0940\u0902! \u0921\u0947\u0932\u094D\u091F\u093E \u0906\u092A\u0915\u093E \u092A\u0948\u0938\u093E \u0939\u0948, \u0906\u092A\u0915\u0947 \u092A\u093E\u0938 \u0907\u0938\u0947 \u092E\u0941\u092B\u093C\u094D\u0924 \u092E\u0947\u0902 \u092A\u094D\u0930\u093E\u092A\u094D\u0924 \u0915\u0930\u0928\u0947 \u0915\u093E \u0905\u0927\u093F\u0915\u093E\u0930 \u0939\u0948, \u0906\u092A\u0915\u094B \u092C\u0938 \u090F\u0915 \u0935\u093F\u0936\u094D\u0935\u0938\u0928\u0940\u092F \u0905\u0928\u0941\u0936\u0902\u0938\u093E\u0915\u0930\u094D\u0924\u093E \u0921\u0940\u0906\u0908\u0921\u0940 \u200B\u200B\u0915\u0940 \u0906\u0935\u0936\u094D\u092F\u0915\u0924\u093E \u0939\u0948\u0964";
