    mobile_first7 = "\u092A\u0939\u0932\u0947 \u092E\u094B\u092C\u093E\u0907\u0932";
    mobile_first_desc6 = "\u0905\u092A\u0928\u0947 \u092E\u094B\u092C\u093E\u0907\u0932 \u092B\u093C\u094B\u0928 \u092A\u0930 \u0935\u093F\u092D\u093F\u0928\u094D\u0928 \u0938\u0941\u0935\u093F\u0927\u093E\u0913\u0902 \u0915\u093E \u0909\u092A\u092F\u094B\u0917 \u0915\u0930\u0928\u093E, \u092E\u093E\u0907\u0928 \u0915\u0930\u0928\u093E \u0914\u0930 \u0909\u0928\u0915\u093E \u0909\u092A\u092F\u094B\u0917 \u0915\u0930\u0928\u093E \u0906\u0938\u093E\u0928 \u0939\u0948";
