    fair_distribution_desc7 = "\u091C\u093E\u0930\u0940 \u0915\u0930\u0928\u0947 \u0915\u0940 \u0935\u093F\u0927\u093F \u0938\u093E\u092E\u0941\u0926\u093E\u092F\u093F\u0915 \u0916\u0928\u0928 \u0914\u0930 \u092A\u093E\u0930\u093F\u0938\u094D\u0925\u093F\u0924\u093F\u0915 \u0928\u093F\u0930\u094D\u092E\u093E\u0923 \u092A\u0941\u0930\u0938\u094D\u0915\u093E\u0930\u094B\u0902 \u0915\u0947 \u092E\u093E\u0927\u094D\u092F\u092E \u0938\u0947 \u0939\u0948, \u092C\u093F\u0928\u093E \u0915\u093F\u0938\u0940 \u092A\u0942\u0930\u094D\u0935-\u092C\u093F\u0915\u094D\u0930\u0940 \u0914\u0930 ICO \u0915\u0947";
