    DAO_governance_model5 = "\u0921\u0940\u090F\u0913 \u0936\u093E\u0938\u0928 \u092E\u0949\u0921\u0932";
    DAO_governance_model_desc5 = "\u0938\u092E\u0938\u094D\u0924 \u092E\u093E\u0928\u0935 \u091C\u093E\u0924\u093F \u0915\u0947 \u0932\u093F\u090F \u0935\u093F\u0915\u0947\u0902\u0926\u094D\u0930\u0940\u0915\u0943\u0924 \u0938\u0939\u092F\u094B\u0917\u093E\u0924\u094D\u092E\u0915 \u0936\u093E\u0938\u0928, \u0938\u0902\u0924\u0941\u0932\u093F\u0924 \u0935\u093F\u0915\u093E\u0938, \u0926\u0940\u0930\u094D\u0918\u0915\u093E\u0932\u093F\u0915 \u0935\u093F\u0936\u094D\u0935\u0938\u0928\u0940\u092F\u0924\u093E";
    explore_delta_heading5 = "\u0921\u0947\u0932\u094D\u091F\u093E \u0915\u0947 \u0930\u0939\u0938\u094D\u092F \u0915\u093E \u0905\u0928\u094D\u0935\u0947\u0937\u0923 \u0915\u0930\u0947\u0902 \u0914\u0930 \u092D\u0935\u093F\u0937\u094D\u092F \u0915\u0947 \u0938\u092E\u093E\u091C \u092E\u0947\u0902 \u0921\u093F\u091C\u093F\u091F\u0932 \u092E\u0941\u0926\u094D\u0930\u093E \u0915\u0940 \u090F\u0915 \u0938\u0902\u092A\u0942\u0930\u094D\u0923 \u092A\u093E\u0930\u093F\u0938\u094D\u0925\u093F\u0924\u093F\u0915 \u0936\u094D\u0930\u0943\u0902\u0916\u0932\u093E \u0915\u093E \u0928\u093F\u0930\u094D\u092E\u093E\u0923 \u0915\u0930\u0947\u0902...";
    access_terminal7 = "\u090F\u0915\u094D\u0938\u0947\u0938 \u091F\u0930\u094D\u092E\u093F\u0928\u0932";
    DSMS_access_terminal_heading6 = "<span style='font-size:large'>DSMS \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u090F\u0915\u094D\u0938\u0947\u0938 \u091F\u0930\u094D\u092E\u093F\u0928\u0932</span> \u0921\u0947\u0932\u094D\u091F\u093E \u0935\u093F\u0915\u0947\u0928\u094D\u0926\u094D\u0930\u0940\u0915\u0943\u0924 \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u0915\u0947 \u0932\u093F\u090F \u090F\u0915 \u090F\u0938\u090F\u092E\u090F\u0938 \u090F\u0915\u094D\u0938\u0947\u0938 \u091F\u0930\u094D\u092E\u093F\u0928\u0932 \u0939\u0948, \u091C\u094B \u0924\u0940\u0928-\u0915\u094B\u0908 \u0938\u0924\u094D\u092F\u093E\u092A\u0928 (\u0915\u094B\u0908 \u0928\u093F\u091C\u0940 \u0915\u0941\u0902\u091C\u0940, \u0915\u094B\u0908 \u0938\u094D\u092E\u0943\u0924\u093F \u0935\u093E\u0915\u094D\u092F\u093E\u0902\u0936, \u0915\u094B\u0908 \u092A\u093E\u0938\u0935\u0930\u094D\u0921 \u0906\u0935\u0936\u094D\u092F\u0915 \u0928\u0939\u0940\u0902) \u0915\u093E \u090F\u0939\u0938\u093E\u0938 \u0915\u0930\u0924\u093E \u0939\u0948\u0964 -\u0938\u092E\u093E\u0927\u093E\u0928 \u0915\u093E \u0905\u0902\u0924\u093F\u092E \u092D\u093E\u0917";
    access_terminal_question16 = "\u0938\u0924\u094D\u092F\u093E\u092A\u0928\u0915\u0930\u094D\u0924\u093E \u092C\u0928\u0928\u0947 \u0915\u0947 \u0915\u094D\u092F\u093E \u0932\u093E\u092D \u0939\u0948\u0902?";
    access_terminal_question26 = "\u0938\u0924\u094D\u092F\u093E\u092A\u0928\u0915\u0930\u094D\u0924\u093E \u0915\u0948\u0938\u0947 \u092C\u0928\u0947\u0902?";
    access_terminal_question36 = "\u0915\u094D\u092F\u093E \u092E\u0941\u091D\u0947 \u091F\u0930\u094D\u092E\u093F\u0928\u0932 \u092A\u094D\u0930\u094B\u0917\u094D\u0930\u093E\u092E \u0921\u093E\u0909\u0928\u0932\u094B\u0921 \u0915\u0930\u0928\u0947 \u0915\u0940 \u0906\u0935\u0936\u094D\u092F\u0915\u0924\u093E \u0939\u0948?";
    access_terminal_question46 = "\u0938\u0924\u094D\u092F\u093E\u092A\u0928\u0915\u0930\u094D\u0924\u093E\u0913\u0902 \u0915\u094B \u0915\u094D\u092F\u093E \u0924\u0948\u092F\u093E\u0930\u0940 \u0915\u0930\u0928\u0947 \u0915\u0940 \u0906\u0935\u0936\u094D\u092F\u0915\u0924\u093E \u0939\u0948?";
    access_terminal_answer16 = "\u091C\u092C\u0915\u093F \u0938\u0924\u094D\u092F\u093E\u092A\u0928\u0915\u0930\u094D\u0924\u093E \u0921\u0947\u0932\u094D\u091F\u093E \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0938\u0941\u0930\u0915\u094D\u0937\u093E \u0915\u0947 \u0932\u093F\u090F \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u0938\u0902\u0938\u093E\u0927\u0928 \u0938\u093E\u091D\u093E \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u0935\u0947 \u0938\u0902\u092C\u0902\u0927\u093F\u0924 \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u092A\u0941\u0930\u0938\u094D\u0915\u093E\u0930 \u092D\u0940 \u092A\u094D\u0930\u093E\u092A\u094D\u0924 \u0915\u0930 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964 \u0938\u0924\u094D\u092F\u093E\u092A\u0928\u0915\u0930\u094D\u0924\u093E \u092A\u0941\u0930\u0938\u094D\u0915\u093E\u0930 \u0928\u093F\u092F\u092E\u094B\u0902 \u0915\u0947 \u0935\u093F\u0935\u0930\u0923 \u0915\u0947 \u0932\u093F\u090F, \u0915\u0943\u092A\u092F\u093E \u0936\u094D\u0935\u0947\u0924 \u092A\u0924\u094D\u0930 \u0915\u0947 \u092A\u094D\u0930\u093E\u0938\u0902\u0917\u093F\u0915 \u0905\u0927\u094D\u092F\u093E\u092F \u0926\u0947\u0916\u0947\u0902\u0964";
    access_terminal_answer26 = '\u0939\u0930 \u0915\u093F\u0938\u0940 \u0915\u0947 \u092A\u093E\u0938 \u0938\u0924\u094D\u092F\u093E\u092A\u0928\u0915\u0930\u094D\u0924\u093E \u092C\u0928\u0928\u0947 \u0915\u093E \u0909\u091A\u093F\u0924 \u092E\u094C\u0915\u093E \u0939\u0948\u0964 \u092F\u0926\u093F \u0906\u092A \u0938\u0924\u094D\u092F\u093E\u092A\u0928\u0915\u0930\u094D\u0924\u093E \u0938\u0926\u0938\u094D\u092F \u092C\u0928\u0928\u093E \u091A\u093E\u0939\u0924\u0947 \u0939\u0948\u0902, \u0924\u094B \u0906\u092A \u0921\u0947\u0932\u094D\u091F\u093E \u0910\u092A \u0915\u0947 "\u092E\u0947\u0928\u0942" \u092A\u0943\u0937\u094D\u0920 \u092E\u0947\u0902 \u092A\u094D\u0930\u0935\u0947\u0936 \u0915\u0930 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0938\u0902\u092C\u0902\u0927\u093F\u0924 \u0936\u0930\u094D\u0924\u094B\u0902 \u0915\u0940 \u091C\u093E\u0902\u091A \u0915\u0930\u0928\u0947 \u0914\u0930 \u0909\u0928\u094D\u0939\u0947\u0902 \u092A\u0942\u0930\u093E \u0915\u0930\u0928\u0947 \u0915\u0947 \u092C\u093E\u0926 "\u0921\u0940\u090F\u0938\u090F\u092E\u090F\u0938 \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u092F\u094B\u0917\u094D\u092F\u0924\u093E" \u092A\u094D\u0930\u0935\u093F\u0937\u094D\u091F\u093F \u092A\u093E \u0938\u0915\u0924\u0947 \u0939\u0948\u0902 \u0938\u0924\u094D\u092F\u093E\u092A\u0928\u0915\u0930\u094D\u0924\u093E \u092C\u0928\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u0926\u094C\u0921\u093C\u0947\u0902\u0964';
    access_terminal_answer36 = "\u0921\u0947\u0932\u094D\u091F\u093E \u0909\u092A\u092F\u094B\u0917\u0915\u0930\u094D\u0924\u093E \u091C\u093F\u0928\u094D\u0939\u094B\u0902\u0928\u0947 \u0938\u0924\u094D\u092F\u093E\u092A\u0928\u0915\u0930\u094D\u0924\u093E \u092F\u094B\u0917\u094D\u092F\u0924\u093E \u092A\u094D\u0930\u093E\u092A\u094D\u0924 \u0928\u0939\u0940\u0902 \u0915\u0940 \u0939\u0948, \u0909\u0928\u094D\u0939\u0947\u0902 \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u091F\u0930\u094D\u092E\u093F\u0928\u0932 \u0921\u093E\u0909\u0928\u0932\u094B\u0921 \u0915\u0930\u0928\u0947 \u0915\u0940 \u0906\u0935\u0936\u094D\u092F\u0915\u0924\u093E \u0928\u0939\u0940\u0902 \u0939\u0948\u0964";
    access_terminal_answer46 = "\u092F\u0926\u093F \u0906\u092A\u0928\u0947 \u090F\u0915 \u0938\u0924\u094D\u092F\u093E\u092A\u0928\u0915\u0930\u094D\u0924\u093E \u0915\u0940 \u092F\u094B\u0917\u094D\u092F\u0924\u093E \u092A\u094D\u0930\u093E\u092A\u094D\u0924 \u0915\u0930 \u0932\u0940 \u0939\u0948, \u0924\u094B \u0906\u092A\u0915\u094B \u090F\u0915 \u0928\u093F\u0937\u094D\u0915\u094D\u0930\u093F\u092F \u0938\u094D\u092E\u093E\u0930\u094D\u091F\u092B\u094B\u0928 \u0914\u0930 \u090F\u0915 \u0938\u092E\u0930\u094D\u092A\u093F\u0924 <span class='underline' title='\u0906\u092E\u0924\u094C\u0930 \u092A\u0930 \u091C\u093E\u0928\u093E \u091C\u093E\u0924\u093E \u0939\u0948: \u092E\u094B\u092C\u093E\u0907\u0932 \u092B\u093C\u094B\u0928 \u0928\u0902\u092C\u0930'>MSISDN</span> \u0924\u0948\u092F\u093E\u0930 \u0915\u0930\u0928\u093E \u0939\u094B\u0917\u093E, \u0914\u0930 \u090F\u0915 \u0905\u091A\u094D\u091B\u093E \u0938\u093F\u0917\u094D\u0928\u0932 \u0939\u094B\u0928\u093E \u091A\u093E\u0939\u093F\u090F \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u091F\u0930\u094D\u092E\u093F\u0928\u0932 \u0938\u094D\u0925\u093E\u092A\u093F\u0924 \u0915\u0930\u0928\u0947 \u0914\u0930 \u0935\u093E\u0938\u094D\u0924\u0935\u093F\u0915 \u0938\u092E\u092F \u092E\u0947\u0902 \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u092A\u0939\u0941\u0902\u091A \u0915\u093E\u0930\u094D\u092F \u0915\u0930\u0928\u0947 \u0915\u0940 \u0936\u0930\u094D\u0924\u0947\u0902\u0964";
