    access_terminal_answer111 = "\uC720\uD6A8\uC131 \uAC80\uC0AC\uC790\uB294 \uB378\uD0C0 \uB124\uD2B8\uC6CC\uD06C \uBCF4\uC548\uC5D0 \uB300\uD55C \uC720\uD6A8\uC131 \uAC80\uC0AC \uB9AC\uC18C\uC2A4\uB97C \uACF5\uC720\uD558\uBA74\uC11C \uD574\uB2F9 \uC720\uD6A8\uC131 \uAC80\uC0AC\uC5D0 \uB300\uD55C \uBCF4\uC0C1\uB3C4 \uBC1B\uC2B5\uB2C8\uB2E4. \uC720\uD6A8\uC131 \uAC80\uC0AC\uC790 \uBCF4\uC0C1 \uADDC\uCE59\uC5D0 \uB300\uD55C \uC790\uC138\uD55C \uB0B4\uC6A9\uC740 \uBC31\uC11C\uC758 \uAD00\uB828 \uC139\uC158\uC744 \uCC38\uC870\uD558\uC138\uC694.";
