    no_password12 = "\u0995\u09CB\u09A8 \u09AA\u09BE\u09B8\u0993\u09AF\u09BC\u09BE\u09B0\u09CD\u09A1 \u09AA\u09CD\u09B0\u09AF\u09BC\u09CB\u099C\u09A8 \u09A8\u09C7\u0987";
    download_delta_application_now13 = "\u098F\u0996\u09A8\u0987 \u09A1\u09C7\u09B2\u09CD\u099F\u09BE \u0985\u09CD\u09AF\u09BE\u09AA \u09A1\u09BE\u0989\u09A8\u09B2\u09CB\u09A1 \u0995\u09B0\u09C1\u09A8";
