    download_heading13 = "\u09A1\u09C7\u09B2\u09CD\u099F\u09BE \u0985\u09CD\u09AF\u09BE\u09AA \u09A1\u09BE\u0989\u09A8\u09B2\u09CB\u09A1 \u0995\u09B0\u09C1\u09A8 \u098F\u09AC\u0982 \u0996\u09A8\u09A8 \u09B6\u09C1\u09B0\u09C1 \u0995\u09B0\u09C1\u09A8 \u098F\u09AC\u0982 \u09B8\u09AE\u09CD\u09AA\u09A6 \u09AA\u09B0\u09BF\u099A\u09BE\u09B2\u09A8\u09BE \u0995\u09B0\u09C1\u09A8... \u098F\u09AC\u0982 \u098F\u0996\u09A8\u0987 \u09AF\u09CB\u0997 \u09A6\u09BF\u09A8!";
    download_desc112 = "\u0986\u0987\u09A8\u09BF \u09AE\u09C1\u09A6\u09CD\u09B0\u09BE\u09B0 \u09E7 \u09B6\u09A4\u09BE\u0982\u09B6 \u09AC\u09BF\u09A8\u09BF\u09AF\u09BC\u09CB\u0997 \u0995\u09B0\u09A4\u09C7 \u09B9\u09AC\u09C7 \u09A8\u09BE! \u09A1\u09C7\u09B2\u09CD\u099F\u09BE \u09B9\u09B2 \u0986\u09AA\u09A8\u09BE\u09B0 \u099F\u09BE\u0995\u09BE, \u0986\u09AA\u09A8\u09BE\u09B0 \u0995\u09BE\u099B\u09C7 \u09AC\u09BF\u09A8\u09BE\u09AE\u09C2\u09B2\u09CD\u09AF\u09C7\u09B0 \u0996\u09A8\u09BF\u09B0 \u0985\u09A7\u09BF\u0995\u09BE\u09B0 \u0986\u099B\u09C7, \u0986\u09AA\u09A8\u09BE\u09B0 \u09B6\u09C1\u09A7\u09C1 \u09AA\u09CD\u09B0\u09AF\u09BC\u09CB\u099C\u09A8 \u098F\u0995\u099C\u09A8 \u09AC\u09BF\u09B6\u09CD\u09AC\u09B8\u09CD\u09A4 \u09B8\u09C1\u09AA\u09BE\u09B0\u09BF\u09B6\u0995\u09BE\u09B0\u09C0 \u09A1\u09BF\u0986\u0987\u09A1\u09BF\u0964";
