    search_find_delta_referrer11 = "\u09A1\u09C7\u09B2\u09CD\u099F\u09BE \u09B8\u09C1\u09AA\u09BE\u09B0\u09BF\u09B6\u0995\u09C3\u09A4 \u09A1\u09BF\u0986\u0987\u09A1\u09BF \u0993\u09AF\u09BC\u09C7\u09AC \u0985\u09A8\u09C1\u09B8\u09A8\u09CD\u09A7\u09BE\u09A8\u09C7\u09B0 \u09AE\u09BE\u09A7\u09CD\u09AF\u09AE\u09C7 \u09AA\u09BE\u0993\u09AF\u09BC\u09BE \u09AF\u09BE\u09AC\u09C7";
    download_desc212 = "\u0986\u09AA\u09A8\u09BE\u09B0 \u09AF\u09A6\u09BF \u0987\u09A4\u09BF\u09AE\u09A7\u09CD\u09AF\u09C7 \u098F\u0995\u099F\u09BF \u09B8\u09C1\u09AA\u09BE\u09B0\u09BF\u09B6\u0995\u09C3\u09A4 \u09A1\u09BF\u0986\u0987\u09A1\u09BF \u09A5\u09BE\u0995\u09C7 \u09A4\u09AC\u09C7 \u0986\u09AA\u09A8\u09BF \u09A1\u09C7\u09B2\u09CD\u099F\u09BE \u0985\u09CD\u09AF\u09BE\u09AA\u099F\u09BF \u09A1\u09BE\u0989\u09A8\u09B2\u09CB\u09A1 \u0995\u09B0\u09A4\u09C7 \u09A8\u09C0\u099A\u09C7\u09B0 \u0986\u0987\u0995\u09A8\u09C7 \u0995\u09CD\u09B2\u09BF\u0995 \u0995\u09B0\u09A4\u09C7 \u09AA\u09BE\u09B0\u09C7\u09A8\u0964";
    decentralization13 = "\u09AC\u09BF\u0995\u09C7\u09A8\u09CD\u09A6\u09CD\u09B0\u09C0\u0995\u09B0\u09A3";
    decentralization_desc12 = "\u09A8\u09BF\u09B0\u09BE\u09AA\u09A6, \u0993\u09AA\u09C7\u09A8 \u09B8\u09CB\u09B0\u09CD\u09B8, \u09B8\u09CD\u09AC\u099A\u09CD\u099B, \u0985\u09AC\u09BF\u09B8\u09CD\u09AE\u09B0\u09A3\u09C0\u09AF\u09BC, \u098F\u09AC\u0982 \u09B8\u09AC\u09BE\u0987 \u0995\u09BE\u09B8\u09CD\u099F\u09BF\u0982 \u098F\u09AC\u0982 \u09B8\u09BE\u09B0\u09CD\u099F\u09BF\u09AB\u09BF\u0995\u09C7\u09B6\u09A8\u09C7 \u0985\u0982\u09B6\u0997\u09CD\u09B0\u09B9\u09A3 \u0995\u09B0\u09C7";
    mobile_first13 = "\u09AA\u09CD\u09B0\u09A5\u09AE\u09C7 \u09AE\u09CB\u09AC\u09BE\u0987\u09B2";
    mobile_first_desc12 = "\u0986\u09AA\u09A8\u09BE\u09B0 \u09AE\u09CB\u09AC\u09BE\u0987\u09B2 \u09AB\u09CB\u09A8\u09C7 \u09AC\u09CD\u09AF\u09AC\u09B9\u09BE\u09B0 \u0995\u09B0\u09BE \u09B8\u09B9\u099C, \u0996\u09A8\u09BF \u098F\u09AC\u0982 \u09AC\u09BF\u09AD\u09BF\u09A8\u09CD\u09A8 \u09AC\u09C8\u09B6\u09BF\u09B7\u09CD\u099F\u09CD\u09AF \u09AC\u09CD\u09AF\u09AC\u09B9\u09BE\u09B0 \u0995\u09B0\u09C1\u09A8";
    environment_friendly13 = "\u09AA\u09B0\u09BF\u09AC\u09C7\u09B6 \u09AC\u09BE\u09A8\u09CD\u09A7\u09AC";
    environment_friendly_desc11 = "\u09AC\u09BF\u09A6\u09CD\u09AF\u09C1\u09A4 \u098F\u09AC\u0982 \u09A8\u09C7\u099F\u0993\u09AF\u09BC\u09BE\u09B0\u09CD\u0995\u09C7\u09B0 \u0985\u09A4\u09BF\u09B0\u09BF\u0995\u09CD\u09A4 \u0996\u09B0\u099A \u09A8\u09C7\u0987, \u09AC\u09A1\u09BC \u09AA\u09B0\u09BF\u09AE\u09BE\u09A3\u09C7 \u09AC\u09C8\u09A6\u09CD\u09AF\u09C1\u09A4\u09BF\u0995 \u09AC\u09B0\u09CD\u099C\u09CD\u09AF \u09A8\u09C7\u0987";
    safety_circle12 = "\u09A8\u09BF\u09B0\u09BE\u09AA\u09A4\u09CD\u09A4\u09BE \u09AC\u09C3\u09A4\u09CD\u09A4";
    safety_circle_desc12 = "\u09B8\u09BE\u09AE\u09BE\u099C\u09BF\u0995 \u09A6\u09CD\u09AC\u09C8\u09A4 \u09A8\u09BF\u09B0\u09BE\u09AA\u09A4\u09CD\u09A4\u09BE \u09AF\u09BE\u099A\u09BE\u0987\u0995\u09B0\u09A3, \u09AA\u09B0\u09BF\u099A\u09AF\u09BC \u09AA\u09CD\u09B0\u09AE\u09BE\u09A3 \u0995\u09CB\u09A8\u09CB \u0995\u09C7\u09A8\u09CD\u09A6\u09CD\u09B0\u09C0\u09AF\u09BC \u09B8\u0982\u09B8\u09CD\u09A5\u09BE\u09B0 \u0989\u09AA\u09B0 \u09A8\u09BF\u09B0\u09CD\u09AD\u09B0 \u0995\u09B0\u09C7 \u09A8\u09BE";
    fair_distribution13 = "\u09A8\u09CD\u09AF\u09BE\u09AF\u09CD\u09AF \u09AC\u09A8\u09CD\u099F\u09A8";
    fair_distribution_desc13 = "\u0987\u09B8\u09CD\u09AF\u09C1 \u09AA\u09A6\u09CD\u09A7\u09A4\u09BF\u099F\u09BF \u0995\u09AE\u09BF\u0989\u09A8\u09BF\u099F\u09BF \u09AE\u09BE\u0987\u09A8\u09BF\u0982 \u098F\u09AC\u0982 \u0987\u0995\u09CB\u09B2\u099C\u09BF\u0995\u09CD\u09AF\u09BE\u09B2 \u0995\u09A8\u09B8\u09CD\u099F\u09CD\u09B0\u09BE\u0995\u09B6\u09A8 \u09AA\u09C1\u09B0\u09B7\u09CD\u0995\u09BE\u09B0\u09C7\u09B0 \u09AE\u09BE\u09A7\u09CD\u09AF\u09AE\u09C7, \u0995\u09CB\u09A8\u0993 \u09AA\u09CD\u09B0\u09BE\u0995-\u09AC\u09BF\u0995\u09CD\u09B0\u09AF\u09BC \u098F\u09AC\u0982 ICO \u099B\u09BE\u09A1\u09BC\u09BE\u0987";
    web3_application_center13 = "\u0993\u09AF\u09BC\u09C7\u09AC 3 \u0985\u09CD\u09AF\u09BE\u09AA\u09CD\u09B2\u09BF\u0995\u09C7\u09B6\u09A8 \u0995\u09C7\u09A8\u09CD\u09A6\u09CD\u09B0";
    web3_application_center_desc13 = "dApp \u0985\u09CD\u09AF\u09BE\u09AA\u09CD\u09B2\u09BF\u0995\u09C7\u09B6\u09A8 \u09AA\u09CD\u09B2\u09BE\u099C\u09BE\u09B0 \u09AE\u09BE\u09A7\u09CD\u09AF\u09AE\u09C7 \u09B8\u09B9\u099C\u09C7\u0987 Web3 \u0985\u09CD\u09AF\u09BE\u09AA\u09CD\u09B2\u09BF\u0995\u09C7\u09B6\u09A8 \u09A4\u09C8\u09B0\u09BF \u098F\u09AC\u0982 \u09AA\u09CD\u09B0\u0995\u09BE\u09B6 \u0995\u09B0\u09C1\u09A8";
    ICP_smart_blockchain13 = "\u0986\u0987\u09B8\u09BF\u09AA\u09BF \u0987\u09A8\u09CD\u099F\u09C7\u09B2\u09BF\u099C\u09C7\u09A8\u09CD\u099F \u09AC\u09CD\u09B2\u0995\u099A\u09C7\u0987\u09A8";
    ICP_smart_blockchain_desc11 = "\u0986\u0987\u09B8\u09BF\u09AA\u09BF \u09B8\u09CD\u09AE\u09BE\u09B0\u09CD\u099F \u0995\u09A8\u09CD\u099F\u09CD\u09B0\u09BE\u0995\u09CD\u099F \u0985\u09AA\u09BE\u09B0\u09C7\u099F\u09BF\u0982 \u09AA\u09CD\u09B2\u09CD\u09AF\u09BE\u099F\u09AB\u09B0\u09CD\u09AE\u09C7\u09B0 \u0989\u09AA\u09B0 \u09AD\u09BF\u09A4\u09CD\u09A4\u09BF \u0995\u09B0\u09C7, \u09A8\u09BF\u09B0\u09BE\u09AA\u09A6, \u09A8\u09BF\u09B0\u09CD\u09AD\u09B0\u09AF\u09CB\u0997\u09CD\u09AF, \u09A6\u0995\u09CD\u09B7 \u0995\u09AE\u09CD\u09AA\u09BF\u0989\u099F\u09BF\u0982, \u09B8\u09C0\u09AE\u09BE\u09B9\u09C0\u09A8 \u09B8\u09AE\u09CD\u09AA\u09CD\u09B0\u09B8\u09BE\u09B0\u09A3";
    DAO_governance_model11 = "DAO \u0997\u09AD\u09B0\u09CD\u09A8\u09C7\u09A8\u09CD\u09B8 \u09AE\u09A1\u09C7\u09B2";
    DAO_governance_model_desc11 = "\u09B8\u09AE\u09B8\u09CD\u09A4 \u09AE\u09BE\u09A8\u09AC\u099C\u09BE\u09A4\u09BF\u09B0 \u099C\u09A8\u09CD\u09AF \u09AC\u09BF\u0995\u09C7\u09A8\u09CD\u09A6\u09CD\u09B0\u09C0\u0995\u09C3\u09A4 \u09B8\u09B9\u09AF\u09CB\u0997\u09BF\u09A4\u09BE\u09AE\u09C2\u09B2\u0995 \u09B6\u09BE\u09B8\u09A8, \u09B8\u09C1\u09B7\u09AE \u0989\u09A8\u09CD\u09A8\u09AF\u09BC\u09A8, \u09A6\u09C0\u09B0\u09CD\u0998\u09AE\u09C7\u09AF\u09BC\u09BE\u09A6\u09C0 \u09A8\u09BF\u09B0\u09CD\u09AD\u09B0\u09AF\u09CB\u0997\u09CD\u09AF\u09A4\u09BE";
    explore_delta_heading11 = "\u09A1\u09C7\u09B2\u09CD\u099F\u09BE\u09B0 \u09B0\u09B9\u09B8\u09CD\u09AF \u0985\u09A8\u09CD\u09AC\u09C7\u09B7\u09A3 \u0995\u09B0\u09C1\u09A8 \u098F\u09AC\u0982 \u09AD\u09AC\u09BF\u09B7\u09CD\u09AF\u09A4\u09C7\u09B0 \u09B8\u09AE\u09BE\u099C\u09C7 \u098F\u0995\u09B8\u09BE\u09A5\u09C7 \u09A1\u09BF\u099C\u09BF\u099F\u09BE\u09B2 \u09AE\u09C1\u09A6\u09CD\u09B0\u09BE\u09B0 \u098F\u0995\u099F\u09BF \u09B8\u09AE\u09CD\u09AA\u09C2\u09B0\u09CD\u09A3 \u09AA\u09B0\u09BF\u09AC\u09C7\u09B6\u0997\u09A4 \u099A\u09C7\u0987\u09A8 \u09A4\u09C8\u09B0\u09BF \u0995\u09B0\u09C1\u09A8...";
    access_terminal13 = "\u0985\u09CD\u09AF\u09BE\u0995\u09CD\u09B8\u09C7\u09B8 \u099F\u09BE\u09B0\u09CD\u09AE\u09BF\u09A8\u09BE\u09B2";
    DSMS_access_terminal_heading12 = "<span style='font-size: larger'>DSMS \u09AF\u09BE\u099A\u09BE\u0987\u0995\u09B0\u09A3 \u0985\u09CD\u09AF\u09BE\u0995\u09CD\u09B8\u09C7\u09B8 \u099F\u09BE\u09B0\u09CD\u09AE\u09BF\u09A8\u09BE\u09B2</span> \u09B9\u09B2 \u09A1\u09C7\u09B2\u09CD\u099F\u09BE \u09AC\u09BF\u0995\u09C7\u09A8\u09CD\u09A6\u09CD\u09B0\u09C0\u09AD\u09C2\u09A4 \u09AF\u09BE\u099A\u09BE\u0987\u0995\u09B0\u09A3\u09C7\u09B0 \u099C\u09A8\u09CD\u09AF \u098F\u0995\u099F\u09BF \u098F\u09B8\u098F\u09AE\u098F\u09B8 \u0985\u09CD\u09AF\u09BE\u0995\u09CD\u09B8\u09C7\u09B8 \u099F\u09BE\u09B0\u09CD\u09AE\u09BF\u09A8\u09BE\u09B2, \u09AF\u09BE \u09A5\u09CD\u09B0\u09BF-\u0995\u09CB\u09A8 \u09AF\u09BE\u099A\u09BE\u0987\u0995\u09B0\u09A3 \u0989\u09AA\u09B2\u09AC\u09CD\u09A7\u09BF \u0995\u09B0\u09C7 (\u0995\u09CB\u09A8 \u09AC\u09CD\u09AF\u0995\u09CD\u09A4\u09BF\u0997\u09A4 \u0995\u09C0, \u0995\u09CB\u09A8\u0993 \u09B8\u09CD\u09AE\u09C3\u09A4\u09BF \u09B6\u09AC\u09CD\u09A6, \u09AA\u09BE\u09B8\u0993\u09AF\u09BC\u09BE\u09B0\u09CD\u09A1\u09C7\u09B0 \u09AA\u09CD\u09B0\u09AF\u09BC\u09CB\u099C\u09A8 \u09A8\u09C7\u0987) - \u09B8\u09AE\u09BE\u09A7\u09BE\u09A8\u09C7\u09B0 \u09B6\u09C7\u09B7 \u0985\u0982\u09B6";
    access_terminal_question112 = "\u09AF\u09BE\u099A\u09BE\u0987\u0995\u09BE\u09B0\u09C0 \u09B9\u0993\u09AF\u09BC\u09BE\u09B0 \u09B8\u09C1\u09AC\u09BF\u09A7\u09BE \u0995\u09C0?";
    access_terminal_question212 = "\u0995\u09BF\u09AD\u09BE\u09AC\u09C7 \u098F\u0995\u099C\u09A8 \u09AF\u09BE\u099A\u09BE\u0987\u0995\u09BE\u09B0\u09C0 \u09B9\u09AC\u09C7\u09A8?";
    access_terminal_question312 = "\u0986\u09AE\u09BE\u09B0 \u0995\u09BF \u099F\u09BE\u09B0\u09CD\u09AE\u09BF\u09A8\u09BE\u09B2 \u09AA\u09CD\u09B0\u09CB\u0997\u09CD\u09B0\u09BE\u09AE \u09A1\u09BE\u0989\u09A8\u09B2\u09CB\u09A1 \u0995\u09B0\u09A4\u09C7 \u09B9\u09AC\u09C7?";
    access_terminal_question412 = "\u09AF\u09BE\u099A\u09BE\u0987\u0995\u09BE\u09B0\u09C0\u09A6\u09C7\u09B0 \u0995\u09BF \u09AA\u09CD\u09B0\u09B8\u09CD\u09A4\u09C1\u09A4 \u0995\u09B0\u09A4\u09C7 \u09B9\u09AC\u09C7?";
    access_terminal_answer112 = "\u09AF\u0996\u09A8 \u09AF\u09BE\u099A\u09BE\u0987\u0995\u09BE\u09B0\u09C0\u09B0\u09BE \u09A1\u09C7\u09B2\u09CD\u099F\u09BE \u09A8\u09C7\u099F\u0993\u09AF\u09BC\u09BE\u09B0\u09CD\u0995 \u09B8\u09C1\u09B0\u0995\u09CD\u09B7\u09BE\u09B0 \u099C\u09A8\u09CD\u09AF \u09AF\u09BE\u099A\u09BE\u0987\u0995\u09B0\u09A3 \u09B8\u0982\u09B8\u09CD\u09A5\u09BE\u09A8\u0997\u09C1\u09B2\u09BF \u09AD\u09BE\u0997 \u0995\u09B0\u09C7, \u09A4\u09BE\u09B0\u09BE \u09B8\u0982\u09B6\u09CD\u09B2\u09BF\u09B7\u09CD\u099F \u09AF\u09BE\u099A\u09BE\u0987 \u09AA\u09C1\u09B0\u09B7\u09CD\u0995\u09BE\u09B0\u0993 \u09AA\u09C7\u09A4\u09C7 \u09AA\u09BE\u09B0\u09C7\u0964 \u09AF\u09BE\u099A\u09BE\u0987\u0995\u09BE\u09B0\u09C0 \u09AA\u09C1\u09B0\u09B8\u09CD\u0995\u09BE\u09B0\u09C7\u09B0 \u09A8\u09BF\u09AF\u09BC\u09AE \u09B8\u09AE\u09CD\u09AA\u09B0\u09CD\u0995\u09C7 \u09AC\u09BF\u09B6\u09A6 \u09AC\u09BF\u09AC\u09B0\u09A3\u09C7\u09B0 \u099C\u09A8\u09CD\u09AF, \u0985\u09A8\u09C1\u0997\u09CD\u09B0\u09B9 \u0995\u09B0\u09C7 \u09B8\u09BE\u09A6\u09BE \u0995\u09BE\u0997\u099C\u09C7\u09B0 \u09AA\u09CD\u09B0\u09BE\u09B8\u0999\u09CD\u0997\u09BF\u0995 \u0985\u09A7\u09CD\u09AF\u09BE\u09AF\u09BC\u0997\u09C1\u09B2\u09BF \u09AA\u09A1\u09BC\u09C1\u09A8\u0964";
    access_terminal_answer212 = '\u09AA\u09CD\u09B0\u09A4\u09CD\u09AF\u09C7\u0995\u09C7\u09B0\u0987 \u09AF\u09BE\u099A\u09BE\u0987\u0995\u09BE\u09B0\u09C0 \u09B9\u0993\u09AF\u09BC\u09BE\u09B0 \u0989\u09AA\u09AF\u09C1\u0995\u09CD\u09A4 \u09B8\u09C1\u09AF\u09CB\u0997 \u09B0\u09AF\u09BC\u09C7\u099B\u09C7, \u0986\u09AA\u09A8\u09BF \u09AF\u09A6\u09BF \u09A1\u09C7\u09B2\u09CD\u099F\u09BE \u0985\u09CD\u09AF\u09BE\u09AA\u09C7\u09B0 "\u09AE\u09C7\u09A8\u09C1" \u09AA\u09C3\u09B7\u09CD\u09A0\u09BE\u09AF\u09BC \u09AA\u09CD\u09B0\u09AC\u09C7\u09B6 \u0995\u09B0\u09A4\u09C7 \u09AA\u09BE\u09B0\u09C7\u09A8 \u098F\u09AC\u0982 \u09AA\u09CD\u09B0\u09BE\u09B8\u0999\u09CD\u0997\u09BF\u0995 \u09B6\u09B0\u09CD\u09A4 \u09AA\u09C2\u09B0\u09A3 \u0995\u09B0\u09BE\u09B0 \u09AA\u09B0\u09C7 "DSMS \u09AF\u09BE\u099A\u09BE\u0987\u0995\u09B0\u09A3 \u09AF\u09CB\u0997\u09CD\u09AF\u09A4\u09BE" \u098F\u09A8\u09CD\u099F\u09CD\u09B0\u09BF \u0996\u09C1\u0981\u099C\u09C7 \u09AA\u09C7\u09A4\u09C7 \u09AA\u09BE\u09B0\u09C7\u09A8 \u09AF\u09BE\u099A\u09BE\u0987\u0995\u09BE\u09B0\u09C0 \u09B9\u09A4\u09C7 \u09A6\u09CC\u09A1\u09BC\u09BE\u09A8\u0964';
    access_terminal_answer312 = "\u09A1\u09C7\u09B2\u09CD\u099F\u09BE \u09AC\u09CD\u09AF\u09AC\u09B9\u09BE\u09B0\u0995\u09BE\u09B0\u09C0 \u09AF\u09BE\u09B0\u09BE \u09AF\u09BE\u099A\u09BE\u0987\u0995\u09BE\u09B0\u09C0\u09B0 \u09AF\u09CB\u0997\u09CD\u09AF\u09A4\u09BE \u0985\u09B0\u09CD\u099C\u09A8 \u0995\u09B0\u09C7\u09A8\u09BF \u09A4\u09BE\u09A6\u09C7\u09B0 \u09AF\u09BE\u099A\u09BE\u0987\u0995\u09B0\u09A3 \u099F\u09BE\u09B0\u09CD\u09AE\u09BF\u09A8\u09BE\u09B2 \u09A1\u09BE\u0989\u09A8\u09B2\u09CB\u09A1 \u0995\u09B0\u09BE\u09B0 \u09A6\u09B0\u0995\u09BE\u09B0 \u09A8\u09C7\u0987\u0964";
    access_terminal_answer412 = "\u0986\u09AA\u09A8\u09BF \u09AF\u09A6\u09BF \u09AF\u09BE\u099A\u09BE\u0987\u0995\u09BE\u09B0\u09C0\u09B0 \u09AF\u09CB\u0997\u09CD\u09AF\u09A4\u09BE \u0985\u09B0\u09CD\u099C\u09A8 \u0995\u09B0\u09C7 \u09A5\u09BE\u0995\u09C7\u09A8, \u09A4\u09BE\u09B9\u09B2\u09C7 \u0986\u09AA\u09A8\u09BE\u0995\u09C7 \u098F\u0995\u099F\u09BF \u09A8\u09BF\u09B7\u09CD\u0995\u09CD\u09B0\u09BF\u09AF\u09BC \u09B8\u09CD\u09AE\u09BE\u09B0\u09CD\u099F\u09AB\u09CB\u09A8 \u098F\u09AC\u0982 \u098F\u0995\u099F\u09BF \u09A1\u09C7\u09A1\u09BF\u0995\u09C7\u099F\u09C7\u09A1 <span class='underline' title='\u09B8\u09BE\u09A7\u09BE\u09B0\u09A3\u09AD\u09BE\u09AC\u09C7 \u09AA\u09B0\u09BF\u099A\u09BF\u09A4: \u09AE\u09CB\u09AC\u09BE\u0987\u09B2 \u09AB\u09CB\u09A8 \u09A8\u09AE\u09CD\u09AC\u09B0'>MSISDN</span> \u09AA\u09CD\u09B0\u09B8\u09CD\u09A4\u09C1\u09A4 \u0995\u09B0\u09A4\u09C7 \u09B9\u09AC\u09C7 \u098F\u09AC\u0982 \u098F\u0995\u099F\u09BF \u09AD\u09BE\u09B2 \u09B8\u0982\u0995\u09C7\u09A4 \u09A5\u09BE\u0995\u09A4\u09C7 \u09B9\u09AC\u09C7\u0964 \u09AF\u09BE\u099A\u09BE\u0987\u0995\u09B0\u09A3 \u099F\u09BE\u09B0\u09CD\u09AE\u09BF\u09A8\u09BE\u09B2 \u0987\u09A8\u09B8\u09CD\u099F\u09B2 \u0995\u09B0\u09BE\u09B0 \u09B6\u09B0\u09CD\u09A4\u09BE\u09AC\u09B2\u09C0 \u098F\u09AC\u0982 \u09B0\u09BF\u09AF\u09BC\u09C7\u09B2 \u099F\u09BE\u0987\u09AE\u09C7 \u09AF\u09BE\u099A\u09BE\u0987\u0995\u09B0\u09A3 \u0985\u09CD\u09AF\u09BE\u0995\u09CD\u09B8\u09C7\u09B8\u09C7\u09B0 \u0995\u09BE\u099C\u0997\u09C1\u09B2\u09BF \u09B8\u09AE\u09CD\u09AA\u09BE\u09A6\u09A8 \u0995\u09B0\u09BE\u0964";
