    download_desc117 = "\u041D\u0435 \u043F\u043E\u0442\u0440\u0456\u0431\u043D\u043E \u0432\u043A\u043B\u0430\u0434\u0430\u0442\u0438 \u043D\u0456 \u0446\u0435\u043D\u0442\u0430 \u043B\u0435\u0433\u0430\u043B\u044C\u043D\u043E\u0457 \u0432\u0430\u043B\u044E\u0442\u0438! \u0414\u0435\u043B\u044C\u0442\u0430 - \u0446\u0435 \u0432\u0430\u0448\u0456 \u0433\u0440\u043E\u0448\u0456, \u0432\u0438 \u043C\u0430\u0454\u0442\u0435 \u043F\u0440\u0430\u0432\u043E \u0434\u043E\u0431\u0443\u0432\u0430\u0442\u0438 \u0457\u0445 \u0431\u0435\u0437\u043A\u043E\u0448\u0442\u043E\u0432\u043D\u043E, \u0432\u0441\u0435, \u0449\u043E \u0432\u0430\u043C \u043F\u043E\u0442\u0440\u0456\u0431\u043D\u043E - \u0446\u0435 \u043D\u0430\u0434\u0456\u0439\u043D\u0438\u0439 <u>\u0440\u0435\u0444\u0435\u0440\u0430\u043B DID</u>.";
