    DAO_governance_model_desc16 = "\u0414\u0435\u0446\u0435\u043D\u0442\u0440\u0430\u043B\u0456\u0437\u043E\u0432\u0430\u043D\u0435 \u0441\u043F\u0456\u043B\u044C\u043D\u0435 \u0443\u043F\u0440\u0430\u0432\u043B\u0456\u043D\u043D\u044F \u0434\u043B\u044F \u0432\u0441\u044C\u043E\u0433\u043E \u043B\u044E\u0434\u0441\u0442\u0432\u0430, \u0437\u0431\u0430\u043B\u0430\u043D\u0441\u043E\u0432\u0430\u043D\u0438\u0439 \u0440\u043E\u0437\u0432\u0438\u0442\u043E\u043A, \u0434\u043E\u0432\u0433\u043E\u0441\u0442\u0440\u043E\u043A\u043E\u0432\u0430 \u043D\u0430\u0434\u0456\u0439\u043D\u0456\u0441\u0442\u044C";
    explore_delta_heading16 = "    \u0414\u043E\u0441\u043B\u0456\u0434\u0456\u0442\u044C \u0442\u0430\u0454\u043C\u043D\u0438\u0446\u044E \u0414\u0435\u043B\u044C\u0442\u0438, <br/> \u0414\u0430\u0432\u0430\u0439\u0442\u0435 \u0440\u0430\u0437\u043E\u043C \u043F\u043E\u0431\u0443\u0434\u0443\u0454\u043C\u043E \u043F\u043E\u0432\u043D\u0438\u0439 \u0435\u043A\u043E\u043B\u043E\u0433\u0456\u0447\u043D\u0438\u0439 \u043B\u0430\u043D\u0446\u044E\u0436\u043E\u043A \u043C\u0430\u0439\u0431\u0443\u0442\u043D\u044C\u043E\u0457 \u0441\u043E\u0446\u0456\u0430\u043B\u044C\u043D\u043E\u0457 \u0446\u0438\u0444\u0440\u043E\u0432\u043E\u0457 \u0432\u0430\u043B\u044E\u0442\u0438...";
    access_terminal18 = "\u0422\u0435\u0440\u043C\u0456\u043D\u0430\u043B \u0434\u043E\u0441\u0442\u0443\u043F\u0443";
    DSMS_access_terminal_heading17 = "<span style='font-size: larger'>\u0422\u0435\u0440\u043C\u0456\u043D\u0430\u043B \u0434\u043E\u0441\u0442\u0443\u043F\u0443 \u0434\u043B\u044F \u0432\u0435\u0440\u0438\u0444\u0456\u043A\u0430\u0446\u0456\u0457 DSMS </span> \u2014 \u0446\u0435 \u0434\u0435\u0446\u0435\u043D\u0442\u0440\u0430\u043B\u0456\u0437\u043E\u0432\u0430\u043D\u0438\u0439 \u0442\u0435\u0440\u043C\u0456\u043D\u0430\u043B \u0434\u043E\u0441\u0442\u0443\u043F\u0443 Delta \u0434\u043B\u044F \u0432\u0435\u0440\u0438\u0444\u0456\u043A\u0430\u0446\u0456\u0457. \u0426\u0435 \u0437\u043E\u0432\u043D\u0456\u0448\u043D\u044F \u0447\u0430\u0441\u0442\u0438\u043D\u0430 \u0440\u0456\u0448\u0435\u043D\u043D\u044F \u0431\u0435\u0437 \u043F\u0435\u0440\u0435\u0432\u0456\u0440\u043A\u0438 (\u0431\u0435\u0437 \u043F\u0440\u0438\u0432\u0430\u0442\u043D\u043E\u0433\u043E \u043A\u043B\u044E\u0447\u0430, \u0431\u0435\u0437 \u043C\u043D\u0435\u043C\u043E\u043D\u0456\u0447\u043D\u043E\u0457 \u0444\u0440\u0430\u0437\u0438, \u0431\u0435\u0437 \u043F\u0430\u0440\u043E\u043B\u044F).";
    access_terminal_question117 = "\u042F\u043A\u0456 \u043F\u0435\u0440\u0435\u0432\u0430\u0433\u0438 \u0434\u0430\u0454 \u0440\u043E\u0431\u043E\u0442\u0430 \u0432\u0430\u043B\u0456\u0434\u0430\u0442\u043E\u0440\u043E\u043C?";
    access_terminal_question217 = "\u042F\u043A \u0441\u0442\u0430\u0442\u0438 \u0432\u0430\u043B\u0456\u0434\u0430\u0442\u043E\u0440\u043E\u043C?";
    access_terminal_question317 = "\u0427\u0438 \u043F\u043E\u0442\u0440\u0456\u0431\u043D\u043E \u0437\u0430\u0432\u0430\u043D\u0442\u0430\u0436\u0443\u0432\u0430\u0442\u0438 \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u0443 \u0442\u0435\u0440\u043C\u0456\u043D\u0430\u043B\u0443?";
    access_terminal_question417 = "\u0429\u043E \u043F\u043E\u0442\u0440\u0456\u0431\u043D\u043E \u043F\u0456\u0434\u0433\u043E\u0442\u0443\u0432\u0430\u0442\u0438 \u0432\u0430\u043B\u0456\u0434\u0430\u0442\u043E\u0440\u0443?";
    access_terminal_answer117 = "\u0425\u043E\u0447\u0430 \u0432\u0430\u043B\u0456\u0434\u0430\u0442\u043E\u0440\u0438 \u0441\u043F\u0456\u043B\u044C\u043D\u043E \u0432\u0438\u043A\u043E\u0440\u0438\u0441\u0442\u043E\u0432\u0443\u044E\u0442\u044C \u0440\u0435\u0441\u0443\u0440\u0441\u0438 \u043F\u0435\u0440\u0435\u0432\u0456\u0440\u043A\u0438 \u0434\u043B\u044F \u0437\u0430\u0431\u0435\u0437\u043F\u0435\u0447\u0435\u043D\u043D\u044F \u0431\u0435\u0437\u043F\u0435\u043A\u0438 \u043C\u0435\u0440\u0435\u0436\u0456 Delta, \u0432\u043E\u043D\u0438 \u0442\u0430\u043A\u043E\u0436 \u043C\u043E\u0436\u0443\u0442\u044C \u043E\u0442\u0440\u0438\u043C\u0443\u0432\u0430\u0442\u0438 \u0432\u0456\u0434\u043F\u043E\u0432\u0456\u0434\u043D\u0456 \u0432\u0438\u043D\u0430\u0433\u043E\u0440\u043E\u0434\u0438 \u0437\u0430 \u043F\u0435\u0440\u0435\u0432\u0456\u0440\u043A\u0443. \u0414\u0435\u0442\u0430\u043B\u044C\u043D\u0456\u0448\u0435 \u043F\u0440\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u0430 \u0432\u0438\u043D\u0430\u0433\u043E\u0440\u043E\u0434\u0438 \u0432\u0430\u043B\u0456\u0434\u0430\u0442\u043E\u0440\u0456\u0432 \u0434\u0438\u0432. \u0443 \u0432\u0456\u0434\u043F\u043E\u0432\u0456\u0434\u043D\u0438\u0445 \u0440\u043E\u0437\u0434\u0456\u043B\u0430\u0445 \u0446\u0456\u0454\u0457 \u0431\u0440\u043E\u0448\u0443\u0440\u0438. \u0414\u043B\u044F \u043E\u0442\u0440\u0438\u043C\u0430\u043D\u043D\u044F \u0434\u0435\u0442\u0430\u043B\u044C\u043D\u043E\u0457 \u0456\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0456\u0457 \u043F\u0440\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u0430 \u0432\u0438\u043D\u0430\u0433\u043E\u0440\u043E\u0434\u0438 \u0432\u0430\u043B\u0456\u0434\u0430\u0442\u043E\u0440\u0456\u0432, \u0431\u0443\u0434\u044C \u043B\u0430\u0441\u043A\u0430, \u0437\u0432\u0435\u0440\u043D\u0456\u0442\u044C\u0441\u044F \u0434\u043E \u0432\u0456\u0434\u043F\u043E\u0432\u0456\u0434\u043D\u0438\u0445 \u0440\u043E\u0437\u0434\u0456\u043B\u0456\u0432 \u0442\u0435\u0445\u043D\u0456\u0447\u043D\u043E\u0457 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u0430\u0446\u0456\u0457.";
    access_terminal_answer217 = '\u042F\u043A\u0449\u043E \u0432\u0438 \u0445\u043E\u0447\u0435\u0442\u0435 \u0441\u0442\u0430\u0442\u0438 \u0432\u0435\u0440\u0438\u0444\u0456\u043A\u0430\u0442\u043E\u0440\u043E\u043C, \u0432\u0438 \u043C\u043E\u0436\u0435\u0442\u0435 \u0437\u0430\u0439\u0442\u0438 \u043D\u0430 \u0441\u0442\u043E\u0440\u0456\u043D\u043A\u0443 "\u041C\u0435\u043D\u044E" \u0434\u043E\u0434\u0430\u0442\u043A\u0443 Delta \u0456 \u0437\u043D\u0430\u0439\u0442\u0438 \u043F\u0443\u043D\u043A\u0442 "\u041A\u0432\u0430\u043B\u0456\u0444\u0456\u043A\u0430\u0446\u0456\u044F \u0432\u0435\u0440\u0438\u0444\u0456\u043A\u0430\u0446\u0456\u0457 DSMS". \u042F\u043A\u0449\u043E \u0432\u0438 \u0445\u043E\u0447\u0435\u0442\u0435 \u0441\u0442\u0430\u0442\u0438 \u0432\u0435\u0440\u0438\u0444\u0456\u043A\u0430\u0442\u043E\u0440\u043E\u043C, \u0432\u0438 \u043C\u043E\u0436\u0435\u0442\u0435 \u0437\u0430\u0439\u0442\u0438 \u043D\u0430 \u0441\u0442\u043E\u0440\u0456\u043D\u043A\u0443 "\u041C\u0435\u043D\u044E" \u0434\u043E\u0434\u0430\u0442\u043A\u0443 Delta \u0456 \u0437\u043D\u0430\u0439\u0442\u0438 \u043F\u0443\u043D\u043A\u0442 "\u041A\u0432\u0430\u043B\u0456\u0444\u0456\u043A\u0430\u0446\u0456\u044F \u0432\u0435\u0440\u0438\u0444\u0456\u043A\u0430\u0446\u0456\u0457 DSMS". \u041F\u0456\u0441\u043B\u044F \u043F\u0435\u0440\u0435\u0432\u0456\u0440\u043A\u0438 \u0442\u0430 \u0432\u0438\u043A\u043E\u043D\u0430\u043D\u043D\u044F \u0432\u0456\u0434\u043F\u043E\u0432\u0456\u0434\u043D\u0438\u0445 \u0443\u043C\u043E\u0432, \u0432\u0438 \u043C\u043E\u0436\u0435\u0442\u0435 \u0441\u0442\u0430\u0442\u0438 \u0432\u0435\u0440\u0438\u0444\u0456\u043A\u0430\u0442\u043E\u0440\u043E\u043C.';
    access_terminal_answer317 = "\u041A\u043E\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u0447\u0430\u043C Delta, \u044F\u043A\u0456 \u043D\u0435 \u043E\u0442\u0440\u0438\u043C\u0430\u043B\u0438 \u043A\u0432\u0430\u043B\u0456\u0444\u0456\u043A\u0430\u0446\u0456\u044E \u0432\u0435\u0440\u0438\u0444\u0456\u043A\u0430\u0442\u043E\u0440\u0430, \u043D\u0435 \u043F\u043E\u0442\u0440\u0456\u0431\u043D\u043E \u0437\u0430\u0432\u0430\u043D\u0442\u0430\u0436\u0443\u0432\u0430\u0442\u0438 \u0432\u0435\u0440\u0438\u0444\u0456\u043A\u0430\u0446\u0456\u0439\u043D\u0438\u0439 \u0442\u0435\u0440\u043C\u0456\u043D\u0430\u043B.";
    access_terminal_answer417 = "\u042F\u043A\u0449\u043E \u0432\u0438 \u043E\u0442\u0440\u0438\u043C\u0430\u043B\u0438 \u043A\u0432\u0430\u043B\u0456\u0444\u0456\u043A\u0430\u0446\u0456\u044E \u0432\u0435\u0440\u0438\u0444\u0456\u043A\u0430\u0442\u043E\u0440\u0430, \u0432\u0430\u043C \u043F\u043E\u0442\u0440\u0456\u0431\u043D\u043E \u043F\u0456\u0434\u0433\u043E\u0442\u0443\u0432\u0430\u0442\u0438 \u043D\u0435\u0430\u043A\u0442\u0438\u0432\u043D\u0438\u0439 \u0441\u043C\u0430\u0440\u0442\u0444\u043E\u043D \u0456 \u0441\u043F\u0435\u0446\u0456\u0430\u043B\u044C\u043D\u0438\u0439 <span class='underline' title='\u0437\u0430\u0433\u0430\u043B\u044C\u043D\u043E \u0432\u0456\u0434\u043E\u043C\u0438\u0439 \u044F\u043A: \u043D\u043E\u043C\u0435\u0440 \u043C\u043E\u0431\u0456\u043B\u044C\u043D\u043E\u0433\u043E \u0442\u0435\u043B\u0435\u0444\u043E\u043D\u0443'>MSISDN</span> \u0456 \u043C\u0430\u0442\u0438 \u0445\u043E\u0440\u043E\u0448\u0438\u0439 \u0441\u0438\u0433\u043D\u0430\u043B \u0423\u043C\u043E\u0432\u0438 \u0432\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u043D\u044F \u0432\u0435\u0440\u0438\u0444\u0456\u043A\u0430\u0446\u0456\u0439\u043D\u0438\u0445 \u0442\u0435\u0440\u043C\u0456\u043D\u0430\u043B\u0456\u0432 \u0442\u0430 \u0432\u0438\u043A\u043E\u043D\u0430\u043D\u043D\u044F \u0437\u0430\u0432\u0434\u0430\u043D\u044C \u043F\u0435\u0440\u0435\u0432\u0456\u0440\u043E\u0447\u043D\u043E\u0433\u043E \u0434\u043E\u0441\u0442\u0443\u043F\u0443 \u0432 \u0440\u0435\u0436\u0438\u043C\u0456 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0447\u0430\u0441\u0443.";
