    decentralization_desc18 = "\u0391\u03C3\u03C6\u03B1\u03BB\u03AE\u03C2, \u03B1\u03BD\u03BF\u03B9\u03BA\u03C4\u03BF\u03CD \u03BA\u03CE\u03B4\u03B9\u03BA\u03B1, \u03B4\u03B9\u03B1\u03C6\u03B1\u03BD\u03AE\u03C2, \u03BC\u03B7 \u03C0\u03B1\u03C1\u03B1\u03C0\u03BF\u03B9\u03AE\u03C3\u03B9\u03BC\u03B7 \u03BA\u03B1\u03B9 \u03CC\u03BB\u03BF\u03B9 \u03C3\u03C5\u03BC\u03BC\u03B5\u03C4\u03AD\u03C7\u03BF\u03C5\u03BD \u03C3\u03C4\u03B7 \u03C7\u03CD\u03C4\u03B5\u03C5\u03C3\u03B7 \u03BA\u03B1\u03B9 \u03C4\u03B7\u03BD \u03C0\u03B9\u03C3\u03C4\u03BF\u03C0\u03BF\u03AF\u03B7\u03C3\u03B7.";
    mobile_first19 = "\u03A0\u03C1\u03CE\u03C4\u03B1 \u03C4\u03BF \u03BA\u03B9\u03BD\u03B7\u03C4\u03CC";
    mobile_first_desc18 = "\u0395\u03CD\u03BA\u03BF\u03BB\u03BF \u03C3\u03C4\u03B7 \u03C7\u03C1\u03AE\u03C3\u03B7, \u03BD\u03B1\u03C1\u03BA\u03BF\u03B8\u03AD\u03C4\u03B7\u03C3\u03B7 \u03BA\u03B1\u03B9 \u03C7\u03C1\u03AE\u03C3\u03B7 \u03B4\u03B9\u03B1\u03C6\u03CC\u03C1\u03C9\u03BD \u03BB\u03B5\u03B9\u03C4\u03BF\u03C5\u03C1\u03B3\u03B9\u03CE\u03BD \u03C3\u03C4\u03BF \u03BA\u03B9\u03BD\u03B7\u03C4\u03CC \u03C3\u03B1\u03C2 \u03C4\u03B7\u03BB\u03AD\u03C6\u03C9\u03BD\u03BF";
    environment_friendly19 = "\u03A6\u03B9\u03BB\u03B9\u03BA\u03CC \u03C0\u03C1\u03BF\u03C2 \u03C4\u03BF \u03C0\u03B5\u03C1\u03B9\u03B2\u03AC\u03BB\u03BB\u03BF\u03BD";
    environment_friendly_desc17 = "\u039A\u03B1\u03BC\u03AF\u03B1 \u03C0\u03C1\u03CC\u03C3\u03B8\u03B5\u03C4\u03B7 \u03BA\u03B1\u03C4\u03B1\u03BD\u03AC\u03BB\u03C9\u03C3\u03B7 \u03B7\u03BB\u03B5\u03BA\u03C4\u03C1\u03B9\u03BA\u03AE\u03C2 \u03B5\u03BD\u03AD\u03C1\u03B3\u03B5\u03B9\u03B1\u03C2 \u03BA\u03B1\u03B9 \u03B4\u03B9\u03BA\u03C4\u03CD\u03BF\u03C5, \u03BA\u03B1\u03BC\u03AF\u03B1 \u03BC\u03B5\u03B3\u03AC\u03BB\u03B7 \u03C0\u03BF\u03C3\u03CC\u03C4\u03B7\u03C4\u03B1 \u03B7\u03BB\u03B5\u03BA\u03C4\u03C1\u03B9\u03BA\u03CE\u03BD \u03B1\u03C0\u03BF\u03B2\u03BB\u03AE\u03C4\u03C9\u03BD";
    safety_circle18 = "\u039A\u03CD\u03BA\u03BB\u03BF\u03C2 \u03B1\u03C3\u03C6\u03B1\u03BB\u03B5\u03AF\u03B1\u03C2";
    safety_circle_desc18 = "\u0397 \u03B5\u03C0\u03B1\u03BB\u03AE\u03B8\u03B5\u03C5\u03C3\u03B7 \u03C4\u03B7\u03C2 \u03BA\u03BF\u03B9\u03BD\u03C9\u03BD\u03B9\u03BA\u03AE\u03C2 \u03B4\u03B9\u03C0\u03BB\u03AE\u03C2 \u03B1\u03C3\u03C6\u03AC\u03BB\u03B5\u03B9\u03B1\u03C2, \u03B7 \u03B1\u03C0\u03CC\u03B4\u03B5\u03B9\u03BE\u03B7 \u03C4\u03B1\u03C5\u03C4\u03CC\u03C4\u03B7\u03C4\u03B1\u03C2 \u03B4\u03B5\u03BD \u03B2\u03B1\u03C3\u03AF\u03B6\u03B5\u03C4\u03B1\u03B9 \u03C3\u03B5 \u03BA\u03B1\u03BD\u03AD\u03BD\u03B1\u03BD \u03BA\u03B5\u03BD\u03C4\u03C1\u03B9\u03BA\u03CC \u03BF\u03C1\u03B3\u03B1\u03BD\u03B9\u03C3\u03BC\u03CC";
    fair_distribution19 = "\u03B4\u03AF\u03BA\u03B1\u03B9\u03B7 \u03BA\u03B1\u03C4\u03B1\u03BD\u03BF\u03BC\u03AE";
    fair_distribution_desc19 = "\u0397 \u03BC\u03AD\u03B8\u03BF\u03B4\u03BF\u03C2 \u03B4\u03B9\u03B1\u03BD\u03BF\u03BC\u03AE\u03C2 \u03B5\u03AF\u03BD\u03B1\u03B9 \u03BC\u03AD\u03C3\u03C9 \u03C4\u03B7\u03C2 \u03BA\u03BF\u03B9\u03BD\u03BF\u03C4\u03B9\u03BA\u03AE\u03C2 \u03B5\u03BE\u03CC\u03C1\u03C5\u03BE\u03B7\u03C2 \u03BA\u03B1\u03B9 \u03C4\u03C9\u03BD \u03B1\u03BD\u03C4\u03B1\u03BC\u03BF\u03B9\u03B2\u03CE\u03BD \u03BF\u03B9\u03BA\u03BF\u03BB\u03BF\u03B3\u03B9\u03BA\u03AE\u03C2 \u03BA\u03B1\u03C4\u03B1\u03C3\u03BA\u03B5\u03C5\u03AE\u03C2, \u03C7\u03C9\u03C1\u03AF\u03C2 \u03C0\u03C1\u03BF\u03C0\u03CE\u03BB\u03B7\u03C3\u03B7 \u03AE ICO.";
    web3_application_center19 = "\u039A\u03AD\u03BD\u03C4\u03C1\u03BF Web3 <u title='Application'>App</u>";
    web3_application_center_desc19 = "\u0395\u03CD\u03BA\u03BF\u03BB\u03B7 \u03B4\u03B7\u03BC\u03B9\u03BF\u03C5\u03C1\u03B3\u03AF\u03B1 \u03BA\u03B1\u03B9 \u03B4\u03B7\u03BC\u03BF\u03C3\u03AF\u03B5\u03C5\u03C3\u03B7 \u03B5\u03C6\u03B1\u03C1\u03BC\u03BF\u03B3\u03CE\u03BD Web3 \u03BC\u03AD\u03C3\u03C9 \u03C4\u03BF\u03C5 dApp Application Plaza";
    ICP_smart_blockchain19 = "ICP smart blockchain";
    ICP_smart_blockchain_desc17 = "\u039C\u03B5 \u03B2\u03AC\u03C3\u03B7 \u03C4\u03B7\u03BD \u03C0\u03BB\u03B1\u03C4\u03C6\u03CC\u03C1\u03BC\u03B1 \u03BB\u03B5\u03B9\u03C4\u03BF\u03C5\u03C1\u03B3\u03AF\u03B1\u03C2 \u03AD\u03BE\u03C5\u03C0\u03BD\u03C9\u03BD \u03C3\u03C5\u03BC\u03B2\u03BF\u03BB\u03B1\u03AF\u03C9\u03BD ICP, \u03B1\u03C3\u03C6\u03B1\u03BB\u03AE\u03C2, \u03B1\u03BE\u03B9\u03CC\u03C0\u03B9\u03C3\u03C4\u03B7, \u03B1\u03C0\u03BF\u03C4\u03B5\u03BB\u03B5\u03C3\u03BC\u03B1\u03C4\u03B9\u03BA\u03AE \u03C5\u03C0\u03BF\u03BB\u03BF\u03B3\u03B9\u03C3\u03C4\u03B9\u03BA\u03AE, \u03B1\u03C0\u03B5\u03C1\u03B9\u03CC\u03C1\u03B9\u03C3\u03C4\u03B7 \u03B5\u03C0\u03AD\u03BA\u03C4\u03B1\u03C3\u03B7";
    DAO_governance_model17 = "\u039C\u03BF\u03BD\u03C4\u03AD\u03BB\u03BF DAO <u title='governance'>gov</u>";
    DAO_governance_model_desc17 = "\u0391\u03C0\u03BF\u03BA\u03B5\u03BD\u03C4\u03C1\u03C9\u03BC\u03AD\u03BD\u03B7 \u03C3\u03C5\u03BD\u03B5\u03C1\u03B3\u03B1\u03C4\u03B9\u03BA\u03AE \u03B4\u03B9\u03B1\u03BA\u03C5\u03B2\u03AD\u03C1\u03BD\u03B7\u03C3\u03B7 \u03B3\u03B9\u03B1 \u03CC\u03BB\u03B7 \u03C4\u03B7\u03BD \u03B1\u03BD\u03B8\u03C1\u03C9\u03C0\u03CC\u03C4\u03B7\u03C4\u03B1, \u03B9\u03C3\u03CC\u03C1\u03C1\u03BF\u03C0\u03B7 \u03B1\u03BD\u03AC\u03C0\u03C4\u03C5\u03BE\u03B7, \u03BC\u03B1\u03BA\u03C1\u03BF\u03C0\u03C1\u03CC\u03B8\u03B5\u03C3\u03BC\u03B7 \u03B1\u03BE\u03B9\u03BF\u03C0\u03B9\u03C3\u03C4\u03AF\u03B1";
    explore_delta_heading17 = "    \u0395\u03BE\u03B5\u03C1\u03B5\u03C5\u03BD\u03AE\u03C3\u03C4\u03B5 \u03C4\u03BF \u03BC\u03C5\u03C3\u03C4\u03AE\u03C1\u03B9\u03BF \u03C4\u03B7\u03C2 \u0394\u03AD\u03BB\u03C4\u03B1, <br/> \u0391\u03C2 \u03C7\u03C4\u03AF\u03C3\u03BF\u03C5\u03BC\u03B5 \u03BC\u03B1\u03B6\u03AF \u03BC\u03B9\u03B1 \u03C0\u03BB\u03AE\u03C1\u03B7 \u03BF\u03B9\u03BA\u03BF\u03BB\u03BF\u03B3\u03B9\u03BA\u03AE \u03B1\u03BB\u03C5\u03C3\u03AF\u03B4\u03B1 \u03C4\u03BF\u03C5 \u03BC\u03B5\u03BB\u03BB\u03BF\u03BD\u03C4\u03B9\u03BA\u03BF\u03CD \u03BA\u03BF\u03B9\u03BD\u03C9\u03BD\u03B9\u03BA\u03BF\u03CD \u03C8\u03B7\u03C6\u03B9\u03B1\u03BA\u03BF\u03CD \u03BD\u03BF\u03BC\u03AF\u03C3\u03BC\u03B1\u03C4\u03BF\u03C2...";
    access_terminal19 = "\u03A4\u03B5\u03C1\u03BC\u03B1\u03C4\u03B9\u03BA\u03CC \u03C0\u03C1\u03CC\u03C3\u03B2\u03B1\u03C3\u03B7\u03C2";
    DSMS_access_terminal_heading18 = "\u03A4\u03BF <span style='font-size: larger'>DSMS verification access terminal</span> \u03B5\u03AF\u03BD\u03B1\u03B9 \u03C4\u03BF \u03B1\u03C0\u03BF\u03BA\u03B5\u03BD\u03C4\u03C1\u03C9\u03BC\u03AD\u03BD\u03BF \u03C4\u03B5\u03C1\u03BC\u03B1\u03C4\u03B9\u03BA\u03CC \u03C0\u03C1\u03CC\u03C3\u03B2\u03B1\u03C3\u03B7\u03C2 SMS \u03B5\u03C0\u03B1\u03BB\u03AE\u03B8\u03B5\u03C5\u03C3\u03B7\u03C2 \u03C4\u03B7\u03C2 Delta \u03BA\u03B1\u03B9 \u03B1\u03C0\u03BF\u03C4\u03B5\u03BB\u03B5\u03AF \u03C4\u03BF front-end \u03BC\u03AD\u03C1\u03BF\u03C2 \u03C4\u03B7\u03C2 \u03BB\u03CD\u03C3\u03B7\u03C2 \u03C4\u03C1\u03B9\u03CE\u03BD \u03BC\u03B7\u03B4\u03B5\u03BD\u03B9\u03BA\u03CE\u03BD \u03B5\u03C0\u03B1\u03BB\u03B7\u03B8\u03B5\u03CD\u03C3\u03B5\u03C9\u03BD (\u03B4\u03B5\u03BD \u03B1\u03C0\u03B1\u03B9\u03C4\u03B5\u03AF\u03C4\u03B1\u03B9 \u03B9\u03B4\u03B9\u03C9\u03C4\u03B9\u03BA\u03CC \u03BA\u03BB\u03B5\u03B9\u03B4\u03AF, \u03BC\u03BD\u03B7\u03BC\u03BF\u03BD\u03B9\u03BA\u03AE \u03C6\u03C1\u03AC\u03C3\u03B7, \u03BA\u03C9\u03B4\u03B9\u03BA\u03CC\u03C2 \u03C0\u03C1\u03CC\u03C3\u03B2\u03B1\u03C3\u03B7\u03C2).";
    access_terminal_question118 = "\u03A0\u03BF\u03B9\u03B1 \u03B5\u03AF\u03BD\u03B1\u03B9 \u03C4\u03B1 \u03BF\u03C6\u03AD\u03BB\u03B7 \u03C4\u03BF\u03C5 \u03BD\u03B1 \u03B3\u03AF\u03BD\u03B5\u03B9\u03C2 \u03B5\u03C0\u03B9\u03BA\u03C5\u03C1\u03C9\u03C4\u03AE\u03C2;";
    access_terminal_question218 = "\u03A0\u03CE\u03C2 \u03BD\u03B1 \u03B3\u03AF\u03BD\u03C9 \u03B5\u03C0\u03B9\u03BA\u03C5\u03C1\u03C9\u03C4\u03AE\u03C2;";
    access_terminal_question318 = "\u03A0\u03C1\u03AD\u03C0\u03B5\u03B9 \u03BD\u03B1 \u03BA\u03B1\u03C4\u03B5\u03B2\u03AC\u03C3\u03C9 \u03C4\u03BF \u03C0\u03C1\u03CC\u03B3\u03C1\u03B1\u03BC\u03BC\u03B1 \u03C4\u03B5\u03C1\u03BC\u03B1\u03C4\u03B9\u03BA\u03BF\u03CD;";
    access_terminal_question418 = "\u03A4\u03B9 \u03C0\u03C1\u03AD\u03C0\u03B5\u03B9 \u03BD\u03B1 \u03C0\u03C1\u03BF\u03B5\u03C4\u03BF\u03B9\u03BC\u03AC\u03C3\u03B5\u03B9 \u03AD\u03BD\u03B1\u03C2 \u03B5\u03C0\u03B9\u03BA\u03C5\u03C1\u03C9\u03C4\u03AE\u03C2;";
    access_terminal_answer118 = "\u0395\u03BD\u03CE \u03BF\u03B9 \u03B5\u03C0\u03B9\u03BA\u03C5\u03C1\u03C9\u03C4\u03AD\u03C2 \u03BC\u03BF\u03B9\u03C1\u03AC\u03B6\u03BF\u03BD\u03C4\u03B1\u03B9 \u03C4\u03BF\u03C5\u03C2 \u03C0\u03CC\u03C1\u03BF\u03C5\u03C2 \u03B5\u03C0\u03B1\u03BB\u03AE\u03B8\u03B5\u03C5\u03C3\u03B7\u03C2 \u03B3\u03B9\u03B1 \u03C4\u03B7\u03BD \u03B1\u03C3\u03C6\u03AC\u03BB\u03B5\u03B9\u03B1 \u03C4\u03BF\u03C5 \u03B4\u03B9\u03BA\u03C4\u03CD\u03BF\u03C5 Delta, \u03BC\u03C0\u03BF\u03C1\u03BF\u03CD\u03BD \u03B5\u03C0\u03AF\u03C3\u03B7\u03C2 \u03BD\u03B1 \u03BB\u03AC\u03B2\u03BF\u03C5\u03BD \u03C4\u03B9\u03C2 \u03B1\u03BD\u03C4\u03AF\u03C3\u03C4\u03BF\u03B9\u03C7\u03B5\u03C2 \u03B1\u03BD\u03C4\u03B1\u03BC\u03BF\u03B9\u03B2\u03AD\u03C2 \u03B5\u03C0\u03B1\u03BB\u03AE\u03B8\u03B5\u03C5\u03C3\u03B7\u03C2. \u0393\u03B9\u03B1 \u03BB\u03B5\u03C0\u03C4\u03BF\u03BC\u03AD\u03C1\u03B5\u03B9\u03B5\u03C2 \u03C3\u03C7\u03B5\u03C4\u03B9\u03BA\u03AC \u03BC\u03B5 \u03C4\u03BF\u03C5\u03C2 \u03BA\u03B1\u03BD\u03CC\u03BD\u03B5\u03C2 \u03B5\u03C0\u03B9\u03B2\u03C1\u03AC\u03B2\u03B5\u03C5\u03C3\u03B7\u03C2 \u03C4\u03C9\u03BD \u03B5\u03C0\u03B9\u03BA\u03C5\u03C1\u03C9\u03C4\u03CE\u03BD, \u03B1\u03BD\u03B1\u03C4\u03C1\u03AD\u03BE\u03C4\u03B5 \u03C3\u03C4\u03B1 \u03C3\u03C7\u03B5\u03C4\u03B9\u03BA\u03AC \u03BA\u03B5\u03C6\u03AC\u03BB\u03B1\u03B9\u03B1 \u03C4\u03B7\u03C2 \u03BB\u03B5\u03C5\u03BA\u03AE\u03C2 \u03B2\u03AF\u03B2\u03BB\u03BF\u03C5.";
    access_terminal_answer218 = '\u038C\u03BB\u03BF\u03B9 \u03AD\u03C7\u03BF\u03C5\u03BD \u03BC\u03B9\u03B1 \u03B4\u03AF\u03BA\u03B1\u03B9\u03B7 \u03B5\u03C5\u03BA\u03B1\u03B9\u03C1\u03AF\u03B1 \u03BD\u03B1 \u03B3\u03AF\u03BD\u03BF\u03C5\u03BD \u03B5\u03C0\u03B1\u03BB\u03B7\u03B8\u03B5\u03C5\u03C4\u03AD\u03C2. \u0391\u03BD \u03B8\u03AD\u03BB\u03B5\u03C4\u03B5 \u03BD\u03B1 \u03B3\u03AF\u03BD\u03B5\u03C4\u03B5 \u03BC\u03AD\u03BB\u03BF\u03C2 \u03B5\u03C0\u03B1\u03BB\u03B7\u03B8\u03B5\u03C5\u03C4\u03AE, \u03BC\u03C0\u03BF\u03C1\u03B5\u03AF\u03C4\u03B5 \u03BD\u03B1 \u03BC\u03C0\u03B5\u03AF\u03C4\u03B5 \u03C3\u03C4\u03B7 \u03C3\u03B5\u03BB\u03AF\u03B4\u03B1 "Menu" \u03C4\u03B7\u03C2 \u03B5\u03C6\u03B1\u03C1\u03BC\u03BF\u03B3\u03AE\u03C2 Delta App \u03BA\u03B1\u03B9 \u03BD\u03B1 \u03B2\u03C1\u03B5\u03AF\u03C4\u03B5 \u03C4\u03B7\u03BD \u03BA\u03B1\u03C4\u03B1\u03C7\u03CE\u03C1\u03B9\u03C3\u03B7 "DSMS Verification Qualification". \u0391\u03C6\u03BF\u03CD \u03B5\u03BB\u03AD\u03B3\u03BE\u03B5\u03C4\u03B5 \u03BA\u03B1\u03B9 \u03B5\u03BA\u03C0\u03BB\u03B7\u03C1\u03CE\u03C3\u03B5\u03C4\u03B5 \u03C4\u03B9\u03C2 \u03C3\u03C7\u03B5\u03C4\u03B9\u03BA\u03AD\u03C2 \u03C0\u03C1\u03BF\u03CB\u03C0\u03BF\u03B8\u03AD\u03C3\u03B5\u03B9\u03C2, \u03BC\u03C0\u03BF\u03C1\u03B5\u03AF\u03C4\u03B5 \u03BD\u03B1 \u03C4\u03C1\u03AD\u03BE\u03B5\u03C4\u03B5 \u03B3\u03B9\u03B1 \u03BD\u03B1 \u03B3\u03AF\u03BD\u03B5\u03C4\u03B5 \u03B5\u03C0\u03B1\u03BB\u03B7\u03B8\u03B5\u03C5\u03C4\u03AE\u03C2.';
    access_terminal_answer318 = "\u039F\u03B9 \u03C7\u03C1\u03AE\u03C3\u03C4\u03B5\u03C2 \u03C4\u03B7\u03C2 Delta \u03C0\u03BF\u03C5 \u03B4\u03B5\u03BD \u03AD\u03C7\u03BF\u03C5\u03BD \u03B1\u03C0\u03BF\u03BA\u03C4\u03AE\u03C3\u03B5\u03B9 \u03C4\u03B1 \u03C0\u03C1\u03BF\u03C3\u03CC\u03BD\u03C4\u03B1 \u03B5\u03C0\u03B1\u03BB\u03B7\u03B8\u03B5\u03C5\u03C4\u03AE \u03B4\u03B5\u03BD \u03C7\u03C1\u03B5\u03B9\u03AC\u03B6\u03B5\u03C4\u03B1\u03B9 \u03BD\u03B1 \u03BA\u03B1\u03C4\u03B5\u03B2\u03AC\u03C3\u03BF\u03C5\u03BD \u03C4\u03BF \u03C4\u03B5\u03C1\u03BC\u03B1\u03C4\u03B9\u03BA\u03CC \u03B5\u03C0\u03B1\u03BB\u03AE\u03B8\u03B5\u03C5\u03C3\u03B7\u03C2.";
    access_terminal_answer418 = "\u0395\u03AC\u03BD \u03AD\u03C7\u03B5\u03C4\u03B5 \u03B1\u03C0\u03BF\u03BA\u03C4\u03AE\u03C3\u03B5\u03B9 \u03C4\u03B1 \u03C0\u03C1\u03BF\u03C3\u03CC\u03BD\u03C4\u03B1 \u03B5\u03C0\u03B1\u03BB\u03B7\u03B8\u03B5\u03C5\u03C4\u03AE, \u03C0\u03C1\u03AD\u03C0\u03B5\u03B9 \u03BD\u03B1 \u03C0\u03C1\u03BF\u03B5\u03C4\u03BF\u03B9\u03BC\u03AC\u03C3\u03B5\u03C4\u03B5 \u03AD\u03BD\u03B1 smartphone \u03C3\u03B5 \u03B1\u03B4\u03C1\u03AC\u03BD\u03B5\u03B9\u03B1 \u03BA\u03B1\u03B9 \u03AD\u03BD\u03B1 \u03B1\u03C0\u03BF\u03BA\u03BB\u03B5\u03B9\u03C3\u03C4\u03B9\u03BA\u03CC <span class='underline' title='\u03BA\u03BF\u03B9\u03BD\u03CE\u03C2 \u03B3\u03BD\u03C9\u03C3\u03C4\u03CC \u03C9\u03C2: mobile phone number'>MSISDN</span> \u03BA\u03B1\u03B9 \u03BD\u03B1 \u03AD\u03C7\u03B5\u03C4\u03B5 \u03BA\u03B1\u03BB\u03CC \u03C3\u03AE\u03BC\u03B1 \u03A0\u03C1\u03BF\u03CB\u03C0\u03BF\u03B8\u03AD\u03C3\u03B5\u03B9\u03C2 \u03B5\u03B3\u03BA\u03B1\u03C4\u03AC\u03C3\u03C4\u03B1\u03C3\u03B7\u03C2 \u03C4\u03B5\u03C1\u03BC\u03B1\u03C4\u03B9\u03BA\u03CE\u03BD \u03B5\u03C0\u03B1\u03BB\u03AE\u03B8\u03B5\u03C5\u03C3\u03B7\u03C2 \u03BA\u03B1\u03B9 \u03B5\u03BA\u03C4\u03AD\u03BB\u03B5\u03C3\u03B7\u03C2 \u03B5\u03C1\u03B3\u03B1\u03C3\u03B9\u03CE\u03BD \u03C0\u03C1\u03CC\u03C3\u03B2\u03B1\u03C3\u03B7\u03C2 \u03B5\u03C0\u03B1\u03BB\u03AE\u03B8\u03B5\u03C5\u03C3\u03B7\u03C2 \u03C3\u03B5 \u03C0\u03C1\u03B1\u03B3\u03BC\u03B1\u03C4\u03B9\u03BA\u03CC \u03C7\u03C1\u03CC\u03BD\u03BF.";
