    fair_distribution20 = "\u0441\u043F\u0440\u0430\u0432\u0435\u0434\u043B\u0438\u0432\u043E \u0440\u0430\u0437\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u0438\u0435";
    fair_distribution_desc20 = "\u041C\u0435\u0442\u043E\u0434\u044A\u0442 \u043D\u0430 \u0435\u043C\u0438\u0442\u0438\u0440\u0430\u043D\u0435 \u0435 \u0447\u0440\u0435\u0437 \u043E\u0431\u0449\u043D\u043E\u0441\u0442\u043D\u043E \u043A\u043E\u043F\u0430\u0435\u043D\u0435 \u0438 \u043D\u0430\u0433\u0440\u0430\u0434\u0438 \u0437\u0430 \u0435\u043A\u043E\u043B\u043E\u0433\u0438\u0447\u043D\u043E \u0441\u0442\u0440\u043E\u0438\u0442\u0435\u043B\u0441\u0442\u0432\u043E, \u0431\u0435\u0437 \u043F\u0440\u0435\u0434\u0432\u0430\u0440\u0438\u0442\u0435\u043B\u043D\u0430 \u043F\u0440\u043E\u0434\u0430\u0436\u0431\u0430 \u0438 ICO.";
    web3_application_center20 = "Web3 <u title='Application'>App</u> Center";
    web3_application_center_desc20 = "\u041B\u0435\u0441\u043D\u043E \u0441\u044A\u0437\u0434\u0430\u0432\u0430\u0439\u0442\u0435 \u0438 \u043F\u0443\u0431\u043B\u0438\u043A\u0443\u0432\u0430\u0439\u0442\u0435 Web3 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u044F \u0447\u0440\u0435\u0437 dApp Application Plaza";
    ICP_smart_blockchain20 = "ICP \u0438\u043D\u0442\u0435\u043B\u0438\u0433\u0435\u043D\u0442\u0435\u043D \u0431\u043B\u043E\u043A\u0447\u0435\u0439\u043D";
    ICP_smart_blockchain_desc18 = "\u0411\u0430\u0437\u0438\u0440\u0430\u043D \u043D\u0430 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u0430 \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u0430 \u0437\u0430 \u0438\u043D\u0442\u0435\u043B\u0438\u0433\u0435\u043D\u0442\u043D\u0438 \u0434\u043E\u0433\u043E\u0432\u043E\u0440\u0438 ICP, \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E, \u043D\u0430\u0434\u0435\u0436\u0434\u043D\u043E, \u0435\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u043E \u0438\u0437\u0447\u0438\u0441\u043B\u0435\u043D\u0438\u0435, \u043D\u0435\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043E \u0440\u0430\u0437\u0448\u0438\u0440\u044F\u0432\u0430\u043D\u0435";
    DAO_governance_model18 = "DAO <u title='\u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435'>gov</u> \u043C\u043E\u0434\u0435\u043B";
    DAO_governance_model_desc18 = "\u0414\u0435\u0446\u0435\u043D\u0442\u0440\u0430\u043B\u0438\u0437\u0438\u0440\u0430\u043D\u043E \u0441\u044A\u0432\u043C\u0435\u0441\u0442\u043D\u043E \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0437\u0430 \u0446\u044F\u043B\u043E\u0442\u043E \u0447\u043E\u0432\u0435\u0447\u0435\u0441\u0442\u0432\u043E, \u0431\u0430\u043B\u0430\u043D\u0441\u0438\u0440\u0430\u043D\u043E \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435, \u0434\u044A\u043B\u0433\u043E\u0441\u0440\u043E\u0447\u043D\u0430 \u043D\u0430\u0434\u0435\u0436\u0434\u043D\u043E\u0441\u0442";
    explore_delta_heading18 = "    \u0418\u0437\u0441\u043B\u0435\u0434\u0432\u0430\u0439\u0442\u0435 \u043C\u0438\u0441\u0442\u0435\u0440\u0438\u044F\u0442\u0430 \u043D\u0430 Delta, <br/> \u041D\u0435\u043A\u0430 \u0437\u0430\u0435\u0434\u043D\u043E \u0438\u0437\u0433\u0440\u0430\u0434\u0438\u043C \u043F\u044A\u043B\u043D\u0430 \u0435\u043A\u043E\u043B\u043E\u0433\u0438\u0447\u043D\u0430 \u0432\u0435\u0440\u0438\u0433\u0430 \u043E\u0442 \u0431\u044A\u0434\u0435\u0449\u0430 \u0441\u043E\u0446\u0438\u0430\u043B\u043D\u0430 \u0446\u0438\u0444\u0440\u043E\u0432\u0430 \u0432\u0430\u043B\u0443\u0442\u0430...";
    access_terminal20 = "\u0422\u0435\u0440\u043C\u0438\u043D\u0430\u043B \u0437\u0430 \u0434\u043E\u0441\u0442\u044A\u043F";
    DSMS_access_terminal_heading19 = "The <span style='font-size: larger'>\u0422\u0435\u0440\u043C\u0438\u043D\u0430\u043B \u0437\u0430 \u0434\u043E\u0441\u0442\u044A\u043F \u0437\u0430 \u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0430 \u043D\u0430 DSMS</span> \u0435 \u0434\u0435\u0446\u0435\u043D\u0442\u0440\u0430\u043B\u0438\u0437\u0438\u0440\u0430\u043D\u0438\u044F\u0442 \u0442\u0435\u0440\u043C\u0438\u043D\u0430\u043B \u0437\u0430 \u0434\u043E\u0441\u0442\u044A\u043F \u0434\u043E SMS \u0437\u0430 \u043F\u043E\u0442\u0432\u044A\u0440\u0436\u0434\u0435\u043D\u0438\u0435 \u043D\u0430 Delta \u0438 \u0435 \u043F\u0440\u0435\u0434\u043D\u0430\u0442\u0430 \u0447\u0430\u0441\u0442 \u043D\u0430 \u0440\u0435\u0448\u0435\u043D\u0438\u0435\u0442\u043E \u0437\u0430 \u0442\u0440\u0438 \u0431\u0435\u0437 \u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0430 (\u0431\u0435\u0437 \u0447\u0430\u0441\u0442\u0435\u043D \u043A\u043B\u044E\u0447, \u0431\u0435\u0437 \u043C\u043D\u0435\u043C\u043E\u043D\u0438\u0447\u043D\u0430 \u0444\u0440\u0430\u0437\u0430, \u0431\u0435\u0437 \u043F\u0430\u0440\u043E\u043B\u0430)";
    access_terminal_question119 = "\u041A\u0430\u043A\u0432\u0438 \u0441\u0430 \u043F\u043E\u043B\u0437\u0438\u0442\u0435 \u043E\u0442 \u0442\u043E\u0432\u0430 \u0434\u0430 \u0441\u0442\u0430\u043D\u0435\u0442\u0435 \u0432\u0430\u043B\u0438\u0434\u0430\u0442\u043E\u0440?";
    access_terminal_question219 = "\u041A\u0430\u043A \u0434\u0430 \u0441\u0442\u0430\u043D\u0435\u0442\u0435 \u0432\u0430\u043B\u0438\u0434\u0430\u0442\u043E\u0440?";
    access_terminal_question319 = "\u0422\u0440\u044F\u0431\u0432\u0430 \u043B\u0438 \u0434\u0430 \u0438\u0437\u0442\u0435\u0433\u043B\u044F \u0442\u0435\u0440\u043C\u0438\u043D\u0430\u043B\u043D\u0430\u0442\u0430 \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u0430?";
    access_terminal_question419 = "\u041A\u0430\u043A\u0432\u043E \u0442\u0440\u044F\u0431\u0432\u0430 \u0434\u0430 \u043F\u043E\u0434\u0433\u043E\u0442\u0432\u0438 \u0435\u0434\u0438\u043D \u0432\u0430\u043B\u0438\u0434\u0430\u0442\u043E\u0440?";
    access_terminal_answer119 = "\u0414\u043E\u043A\u0430\u0442\u043E \u0432\u0430\u043B\u0438\u0434\u0430\u0442\u043E\u0440\u0438\u0442\u0435 \u0441\u043F\u043E\u0434\u0435\u043B\u044F\u0442 \u0440\u0435\u0441\u0443\u0440\u0441\u0438 \u0437\u0430 \u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0430 \u0437\u0430 \u043C\u0440\u0435\u0436\u043E\u0432\u0430 \u0441\u0438\u0433\u0443\u0440\u043D\u043E\u0441\u0442 \u043D\u0430 Delta, \u0442\u0435 \u0441\u044A\u0449\u043E \u043C\u043E\u0433\u0430\u0442 \u0434\u0430 \u043F\u043E\u043B\u0443\u0447\u0430\u0442 \u0441\u044A\u043E\u0442\u0432\u0435\u0442\u043D\u0438\u0442\u0435 \u043D\u0430\u0433\u0440\u0430\u0434\u0438 \u0437\u0430 \u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0430. \u0417\u0430 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E\u0441\u0442\u0438 \u043E\u0442\u043D\u043E\u0441\u043D\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u0430\u0442\u0430 \u0437\u0430 \u0432\u044A\u0437\u043D\u0430\u0433\u0440\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u043D\u0430 \u0432\u0430\u043B\u0438\u0434\u0430\u0442\u043E\u0440\u0430, \u043C\u043E\u043B\u044F, \u0432\u0438\u0436\u0442\u0435 \u0441\u044A\u043E\u0442\u0432\u0435\u0442\u043D\u0438\u0442\u0435 \u0433\u043B\u0430\u0432\u0438 \u043D\u0430 \u0431\u044F\u043B\u0430\u0442\u0430 \u043A\u043D\u0438\u0433\u0430.";
    access_terminal_answer219 = '\u0412\u0441\u0435\u043A\u0438 \u0438\u043C\u0430 \u0441\u043F\u0440\u0430\u0432\u0435\u0434\u043B\u0438\u0432 \u0448\u0430\u043D\u0441 \u0434\u0430 \u0441\u0442\u0430\u043D\u0435 \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0442\u043E\u0440. \u0410\u043A\u043E \u0438\u0441\u043A\u0430\u0442\u0435 \u0434\u0430 \u0441\u0442\u0430\u043D\u0435\u0442\u0435 \u0447\u043B\u0435\u043D \u043D\u0430 \u043F\u0440\u043E\u0432\u0435\u0440\u044F\u0432\u0430\u0449, \u043C\u043E\u0436\u0435\u0442\u0435 \u0434\u0430 \u0432\u043B\u0435\u0437\u0435\u0442\u0435 \u0432 \u0441\u0442\u0440\u0430\u043D\u0438\u0446\u0430\u0442\u0430 "\u041C\u0435\u043D\u044E" \u043D\u0430 Delta App \u0438 \u0434\u0430 \u043D\u0430\u043C\u0435\u0440\u0438\u0442\u0435 \u0437\u0430\u043F\u0438\u0441\u0430 "\u041A\u0432\u0430\u043B\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F \u0437\u0430 \u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0430 \u043D\u0430 DSMS". \u0421\u043B\u0435\u0434 \u043A\u0430\u0442\u043E \u043F\u0440\u043E\u0432\u0435\u0440\u0438\u0442\u0435 \u0438 \u0438\u0437\u043F\u044A\u043B\u043D\u0438\u0442\u0435 \u0441\u044A\u043E\u0442\u0432\u0435\u0442\u043D\u0438\u0442\u0435 \u0443\u0441\u043B\u043E\u0432\u0438\u044F, \u043C\u043E\u0436\u0435\u0442\u0435 \u0434\u0430 \u043A\u0430\u043D\u0434\u0438\u0434\u0430\u0442\u0441\u0442\u0432\u0430\u0442\u0435 \u0437\u0430 \u043F\u0440\u043E\u0432\u0435\u0440\u044F\u0432\u0430\u0449.';
    access_terminal_answer319 = "\u041F\u043E\u0442\u0440\u0435\u0431\u0438\u0442\u0435\u043B\u0438\u0442\u0435 \u043D\u0430 Delta, \u043A\u043E\u0438\u0442\u043E \u043D\u0435 \u0441\u0430 \u043F\u043E\u043B\u0443\u0447\u0438\u043B\u0438 \u043A\u0432\u0430\u043B\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F \u0437\u0430 \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0442\u043E\u0440, \u043D\u0435 \u0442\u0440\u044F\u0431\u0432\u0430 \u0434\u0430 \u0438\u0437\u0442\u0435\u0433\u043B\u044F\u0442 \u0442\u0435\u0440\u043C\u0438\u043D\u0430\u043B\u0430 \u0437\u0430 \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F.";
    access_terminal_answer419 = "\u0410\u043A\u043E \u0441\u0442\u0435 \u043F\u043E\u043B\u0443\u0447\u0438\u043B\u0438 \u043A\u0432\u0430\u043B\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F \u0437\u0430 \u0443\u0434\u043E\u0441\u0442\u043E\u0432\u0435\u0440\u044F\u0432\u0430\u043D\u0435, \u0442\u0440\u044F\u0431\u0432\u0430 \u0434\u0430 \u043F\u043E\u0434\u0433\u043E\u0442\u0432\u0438\u0442\u0435 \u043D\u0435\u0430\u043A\u0442\u0438\u0432\u0435\u043D \u0441\u043C\u0430\u0440\u0442\u0444\u043E\u043D \u0438 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0435\u043D <span class='underline' title='\u041E\u0431\u0449\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u0435\u043D \u043A\u0430\u0442\u043E: \u043D\u043E\u043C\u0435\u0440 \u043D\u0430 \u043C\u043E\u0431\u0438\u043B\u0435\u043D \u0442\u0435\u043B\u0435\u0444\u043E\u043D'>MSISDN</span> \u0438 \u0434\u0430 \u0438\u043C\u0430\u0442\u0435 \u0434\u043E\u0431\u0440\u0438 \u0443\u0441\u043B\u043E\u0432\u0438\u044F \u0437\u0430 \u0441\u0438\u0433\u043D\u0430\u043B, \u0437\u0430 \u0434\u0430 \u0438\u043D\u0441\u0442\u0430\u043B\u0438\u0440\u0430\u0442\u0435 \u0442\u0435\u0440\u043C\u0438\u043D\u0430\u043B\u0430 \u0437\u0430 \u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0430 \u0438 \u0434\u0430 \u0438\u0437\u043F\u044A\u043B\u043D\u044F\u0432\u0430\u0442\u0435 \u0437\u0430\u0434\u0430\u0447\u0438 \u0437\u0430 \u0434\u043E\u0441\u0442\u044A\u043F \u0437\u0430 \u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0430 \u0432 \u0440\u0435\u0430\u043B\u043D\u043E \u0432\u0440\u0435\u043C\u0435.";
