    environment_friendly21 = "\u0698\u06CC\u0646\u06AF\u06D5 \u062F\u06C6\u0633\u062A\u06CC";
    environment_friendly_desc19 = "\u0646\u06D5 \u0628\u06D5\u06A9\u0627\u0631\u0647\u06CE\u0646\u0627\u0646\u06CC \u06A9\u0627\u0631\u06D5\u0628\u0627 \u0648 \u062A\u06C6\u0695\u06CC \u0632\u06CC\u0627\u062F\u06D5\u060C \u0646\u06D5 \u0628\u0695\u06CE\u06A9\u06CC \u0632\u06C6\u0631 \u067E\u0627\u0634\u0645\u0627\u0648\u06D5\u06CC \u06A9\u0627\u0631\u06D5\u0628\u0627";
    safety_circle20 = "\u0628\u0627\u0632\u0646\u06D5\u06CC \u0633\u06D5\u0644\u0627\u0645\u06D5\u062A\u06CC";
    safety_circle_desc20 = "\u067E\u0634\u062A\u0695\u0627\u0633\u062A\u06A9\u0631\u062F\u0646\u06D5\u0648\u06D5\u06CC \u062F\u0648\u0648 \u0626\u0627\u0633\u0627\u06CC\u0634\u06CC \u06A9\u06C6\u0645\u06D5\u06B5\u0627\u06CC\u06D5\u062A\u06CC\u060C \u0628\u06D5\u06B5\u06AF\u06D5\u06CC \u0646\u0627\u0633\u0646\u0627\u0645\u06D5 \u067E\u0634\u062A \u0628\u06D5 \u0647\u06CC\u0686 \u0695\u06CE\u06A9\u062E\u0631\u0627\u0648\u06CE\u06A9\u06CC \u0646\u0627\u0648\u06D5\u0646\u062F\u06CC \u0646\u0627\u0628\u06D5\u0633\u062A\u06CE\u062A";
    fair_distribution21 = "\u062F\u0627\u0628\u06D5\u0634\u06A9\u0631\u062F\u0646\u06CC \u062F\u0627\u062F\u067E\u06D5\u0631\u0648\u06D5\u0631\u0627\u0646\u06D5";
    fair_distribution_desc21 = "\u0634\u06CE\u0648\u0627\u0632\u06CC \u062F\u06D5\u0631\u06A9\u0631\u062F\u0646\u06D5\u06A9\u06D5 \u0644\u06D5 \u0695\u06CE\u06AF\u06D5\u06CC \u067E\u0627\u062F\u0627\u0634\u062A\u06CC \u06A9\u0627\u0646\u06AF\u0627\u06A9\u0631\u062F\u0646\u06CC \u06A9\u06C6\u0645\u06D5\u06B5\u0627\u06CC\u06D5\u062A\u06CC \u0648 \u0628\u06CC\u0646\u0627\u0633\u0627\u0632\u06CC \u0626\u06CC\u06A9\u06C6\u0644\u06C6\u0698\u06CC\u06CC\u06D5\u0648\u06D5\u06CC\u06D5\u060C \u0628\u06D5\u0628\u06CE \u0647\u06CC\u0686 \u067E\u06CE\u0634 \u0641\u0631\u06C6\u0634\u062A\u0646 \u0648 ICO";
    web3_application_center21 = "Web3 <u title='Application'>App</u> Center";
    web3_application_center_desc21 = "\u0628\u06D5 \u0626\u0627\u0633\u0627\u0646\u06CC \u0628\u06D5\u0631\u0646\u0627\u0645\u06D5\u06A9\u0627\u0646\u06CC Web3 \u062F\u0631\u0648\u0633\u062A \u0628\u06A9\u06D5 \u0648 \u0628\u06B5\u0627\u0648\u06CC \u0628\u06A9\u06D5\u0631\u06D5\u0648\u06D5 \u0644\u06D5 \u0695\u06CE\u06AF\u06D5\u06CC dApp Application Plaza";
    ICP_smart_blockchain21 = "\u0628\u0644\u06C6\u06A9\u0686\u06D5\u06CC\u0646\u06CC \u0632\u06CC\u0631\u06D5\u06A9\u06CC ICP";
    ICP_smart_blockchain_desc19 = "\u0644\u06D5\u0633\u06D5\u0631 \u0628\u0646\u06D5\u0645\u0627\u06CC \u067E\u0644\u0627\u062A\u0641\u06C6\u0631\u0645\u06CC \u06A9\u0627\u0631\u067E\u06CE\u06A9\u0631\u062F\u0646\u06CC \u06AF\u0631\u06CE\u0628\u06D5\u0633\u062A\u06CC \u0632\u06CC\u0631\u06D5\u06A9\u06CC ICP\u060C \u0633\u06D5\u0644\u0627\u0645\u06D5\u062A\u060C \u0645\u062A\u0645\u0627\u0646\u06D5\u067E\u06CE\u06A9\u0631\u0627\u0648\u060C \u06A9\u06C6\u0645\u067E\u06CC\u0648\u062A\u06D5\u0631\u06CC \u06A9\u0627\u0631\u0627\u060C \u0641\u0631\u0627\u0648\u0627\u0646\u06A9\u0631\u062F\u0646\u06CC \u0628\u06CE\u0633\u0646\u0648\u0648\u0631";
    DAO_governance_model19 = "DAO <u title='governance'>gov</u> \u0645\u06C6\u062F\u06CC\u06B5";
    DAO_governance_model_desc19 = "\u062D\u0648\u06A9\u0645\u0695\u0627\u0646\u06CC \u0647\u0627\u0648\u0628\u06D5\u0634\u06CC \u0644\u0627\u0645\u06D5\u0631\u06A9\u06D5\u0632\u06CC \u0628\u06C6 \u0647\u06D5\u0645\u0648\u0648 \u0645\u0631\u06C6\u06A4\u0627\u06CC\u06D5\u062A\u06CC\u060C \u06AF\u06D5\u0634\u06D5\u067E\u06CE\u062F\u0627\u0646\u06CC \u0647\u0627\u0648\u0633\u06D5\u0646\u06AF\u060C \u0645\u062A\u0645\u0627\u0646\u06D5\u067E\u06CE\u06A9\u0631\u0627\u0648\u06CC \u062F\u0631\u06CE\u0698\u062E\u0627\u06CC\u06D5\u0646";
    explore_delta_heading19 = "    \u0628\u06D5\u062F\u0648\u0627\u062F\u0627\u0686\u0648\u0648\u0646 \u0628\u06C6 \u0646\u0647\u06CE\u0646\u06CC\u06CC\u06D5\u06A9\u0627\u0646\u06CC \u062F\u06CE\u06B5\u062A\u0627\u060C<br/> \u0628\u0627 \u067E\u06CE\u06A9\u06D5\u0648\u06D5 \u0632\u0646\u062C\u06CC\u0631\u06D5\u06CC\u06D5\u06A9\u06CC \u0626\u06CC\u06A9\u06C6\u0644\u06C6\u0698\u06CC \u062A\u06D5\u0648\u0627\u0648 \u0644\u06D5 \u062F\u0631\u0627\u0648\u06CC \u062F\u06CC\u062C\u06CC\u062A\u0627\u06B5\u06CC \u06A9\u06C6\u0645\u06D5\u06B5\u0627\u06CC\u06D5\u062A\u06CC \u062F\u0627\u0647\u0627\u062A\u0648\u0648 \u062F\u0631\u0648\u0633\u062A \u0628\u06A9\u06D5\u06CC\u0646...";
    access_terminal21 = "\u062A\u06CE\u0631\u0645\u06CC\u0646\u0627\u06B5\u06CC \u062F\u06D5\u0633\u062A\u06AF\u06D5\u06CC\u0634\u062A\u0646";
    DSMS_access_terminal_heading20 = "\u0626\u06D5\u0645\u06D5 <span style='font-size: larger'>DSMS verification access terminal</span>   \u062A\u06CE\u0631\u0645\u06CC\u0646\u0627\u06B5\u06CC \u062F\u06D5\u0633\u062A\u0695\u0627\u06AF\u06D5\u06CC\u0634\u062A\u0646 \u0628\u06D5 \u06A9\u0648\u0631\u062A\u06D5\u0646\u0627\u0645\u06D5\u06CC \u067E\u0634\u062A\u0695\u0627\u0633\u062A\u06A9\u0631\u062F\u0646\u06D5\u0648\u06D5\u06CC \u0644\u0627\u0645\u06D5\u0631\u06A9\u06D5\u0632\u06CC Delta \u06D5 \u0648 \u0628\u06D5\u0634\u06CC \u067E\u06CE\u0634\u06D5\u0648\u06D5\u06CC \u0686\u0627\u0631\u06D5\u0633\u06D5\u0631\u06CC \u0633\u06CE-\u0628\u06CE \u067E\u0634\u062A\u0695\u0627\u0633\u062A\u06A9\u0631\u062F\u0646\u06D5\u0648\u06D5 (\u0628\u06CE \u06A9\u0644\u06CC\u0644\u06CC \u062A\u0627\u06CC\u0628\u06D5\u062A\u060C \u0647\u06CC\u0686 \u062F\u06D5\u0633\u062A\u06D5\u0648\u0627\u0698\u06D5\u06CC\u06D5\u06A9\u06CC \u06CC\u0627\u062F\u06D5\u0648\u06D5\u0631\u06CC\u060C \u0647\u06CC\u0686 \u0648\u0634\u06D5\u06CC \u0646\u0647\u06CE\u0646\u06CC \u067E\u06CE\u0648\u06CC\u0633\u062A \u0646\u06CC\u06CC\u06D5).";
    access_terminal_question120 = "\u0633\u0648\u0648\u062F\u06D5\u06A9\u0627\u0646\u06CC \u0628\u0648\u0648\u0646 \u0628\u06D5 \u0686\u06D5\u0633\u067E\u06CE\u0646\u06D5\u0631 \u0686\u06CC\u0646\u061F";
    access_terminal_question220 = "\u0686\u06C6\u0646 \u0628\u0628\u06CC\u062A\u06D5 \u0686\u06D5\u0633\u067E\u06CE\u0646\u06D5\u0631\u061F";
    access_terminal_question320 = "\u0626\u0627\u06CC\u0627 \u067E\u06CE\u0648\u06CC\u0633\u062A\u06D5 \u0628\u06D5\u0631\u0646\u0627\u0645\u06D5\u06CC \u062A\u06CE\u0631\u0645\u06CC\u0646\u0627\u06B5\u06D5\u06A9\u06D5 \u062F\u0627\u0628\u06D5\u0632\u06CE\u0646\u0645\u061F";
    access_terminal_question420 = "\u0686\u06D5\u0633\u067E\u06CE\u0646\u06D5\u0631 \u067E\u06CE\u0648\u06CC\u0633\u062A\u06CC \u0628\u06D5 \u0686\u06CC\u06CC\u06D5 \u0628\u06C6 \u0626\u0627\u0645\u0627\u062F\u06D5\u06A9\u0627\u0631\u06CC\u061F";
    access_terminal_answer120 = "\u0644\u06D5 \u06A9\u0627\u062A\u06CE\u06A9\u062F\u0627 \u06A9\u06D5 \u0686\u06D5\u0633\u067E\u06CE\u0646\u06D5\u0631\u0627\u0646 \u0633\u06D5\u0631\u0686\u0627\u0648\u06D5\u06CC \u067E\u0634\u062A\u0695\u0627\u0633\u062A\u06A9\u0631\u062F\u0646\u06D5\u0648\u06D5 \u0628\u06C6 \u0626\u0627\u0633\u0627\u06CC\u0634\u06CC \u062A\u06C6\u0695\u06CC \u062F\u06CE\u06B5\u062A\u0627 \u0647\u0627\u0648\u0628\u06D5\u0634 \u062F\u06D5\u06A9\u06D5\u0646\u060C \u062F\u06D5\u062A\u0648\u0627\u0646\u0646 \u067E\u0627\u062F\u0627\u0634\u062A\u06CC \u067E\u0634\u062A\u0695\u0627\u0633\u062A\u06A9\u0631\u062F\u0646\u06D5\u0648\u06D5\u06CC \u0647\u0627\u0648\u062A\u0627 \u0628\u06D5\u062F\u06D5\u0633\u062A\u0628\u0647\u06CE\u0646\u0646. \u0628\u06C6 \u0632\u0627\u0646\u06CC\u0627\u0631\u06CC \u0632\u06CC\u0627\u062A\u0631 \u0644\u06D5\u0633\u06D5\u0631 \u06CC\u0627\u0633\u0627\u06A9\u0627\u0646\u06CC \u067E\u0627\u062F\u0627\u0634\u062A\u06CC \u0686\u06D5\u0633\u067E\u06CE\u0646\u06D5\u0631\u060C \u062A\u06A9\u0627\u06CC\u06D5 \u0626\u0627\u0645\u0627\u0698\u06D5 \u0628\u06D5 \u0628\u0627\u0628\u06D5\u062A\u06D5 \u067E\u06D5\u06CC\u0648\u06D5\u0646\u062F\u06CC\u062F\u0627\u0631\u06D5\u06A9\u0627\u0646\u06CC \u0648\u06D5\u0631\u06D5\u0642\u06D5 \u0633\u067E\u06CC\u06CC\u06D5\u06A9\u06D5 \u0628\u06A9\u06D5\u0646.";
    access_terminal_answer220 = '\u0647\u06D5\u0645\u0648\u0648 \u06A9\u06D5\u0633\u06CE\u06A9 \u0686\u0627\u0646\u0633\u06CC \u062F\u0627\u062F\u067E\u06D5\u0631\u0648\u06D5\u0631\u0627\u0646\u06D5\u06CC \u0647\u06D5\u06CC\u06D5 \u06A9\u06D5 \u0628\u0628\u06CE\u062A\u06D5 \u067E\u0634\u062A\u0695\u0627\u0633\u062A\u06A9\u06D5\u0631\u06D5\u0648\u06D5. \u0626\u06D5\u06AF\u06D5\u0631 \u062F\u06D5\u062A\u06D5\u0648\u06CE\u062A \u0628\u0628\u06CC\u062A\u06D5 \u0626\u06D5\u0646\u062F\u0627\u0645\u06CC \u067E\u0634\u062A\u0695\u0627\u0633\u062A\u06A9\u06D5\u0631\u06D5\u0648\u06D5\u060C \u062F\u06D5\u062A\u0648\u0627\u0646\u06CC\u062A \u0628\u0686\u06CC\u062A\u06D5 \u0646\u0627\u0648... "Menu" \u0644\u0627\u067E\u06D5\u0695\u06D5\u06CC Delta App \u0648 \u062F\u06C6\u0632\u06CC\u0646\u06D5\u0648\u06D5\u06CC..."DSMS \u0628\u0695\u0648\u0627\u0646\u0627\u0645\u06D5\u06CC \u067E\u0634\u062A\u0695\u0627\u0633\u062A\u06A9\u0631\u062F\u0646\u06D5\u0648\u06D5" \u0647\u0627\u062A\u0646\u06D5 \u0698\u0648\u0648\u0631\u06D5\u0648\u06D5. \u062F\u0648\u0627\u06CC \u067E\u0634\u06A9\u0646\u06CC\u0646 \u0648 \u062C\u06CE\u0628\u06D5\u062C\u06CE\u06A9\u0631\u062F\u0646\u06CC \u0645\u06D5\u0631\u062C\u06D5 \u067E\u06D5\u06CC\u0648\u06D5\u0646\u062F\u06CC\u062F\u0627\u0631\u06D5\u06A9\u0627\u0646\u060C \u062F\u06D5\u062A\u0648\u0627\u0646\u06CC\u062A \u0695\u0627\u0628\u06A9\u06D5\u06CC\u062A \u0628\u06C6 \u0626\u06D5\u0648\u06D5\u06CC \u0628\u0628\u06CC\u062A\u06D5 \u067E\u0634\u062A\u0695\u0627\u0633\u062A\u06A9\u06D5\u0631\u06D5\u0648\u06D5.';
    access_terminal_answer320 = "\u0626\u06D5\u0648 \u0628\u06D5\u06A9\u0627\u0631\u0647\u06CE\u0646\u06D5\u0631\u0627\u0646\u06D5\u06CC \u062F\u06CE\u06B5\u062A\u0627 \u06A9\u06D5 \u0628\u0695\u0648\u0627\u0646\u0627\u0645\u06D5\u06CC \u067E\u0634\u062A\u0695\u0627\u0633\u062A\u06A9\u06D5\u0631\u06D5\u0648\u06D5\u06CC\u0627\u0646 \u0628\u06D5\u062F\u06D5\u0633\u062A \u0646\u06D5\u0647\u06CE\u0646\u0627\u0648\u06D5 \u067E\u06CE\u0648\u06CC\u0633\u062A \u0646\u0627\u06A9\u0627\u062A \u062A\u06CE\u0631\u0645\u06CC\u0646\u0627\u06B5\u06CC \u067E\u0634\u062A\u0695\u0627\u0633\u062A\u06A9\u0631\u062F\u0646\u06D5\u0648\u06D5 \u062F\u0627\u0628\u06D5\u0632\u06CE\u0646\u0646.";
    access_terminal_answer420 = "\u0626\u06D5\u06AF\u06D5\u0631 \u0628\u0695\u0648\u0627\u0646\u0627\u0645\u06D5\u06CC \u0695\u06D5\u0633\u06D5\u0646\u0627\u06CC\u06D5\u062A\u06CC\u062A \u0628\u06D5\u062F\u06D5\u0633\u062A\u0647\u06CE\u0646\u0627\u0648\u06D5\u060C \u067E\u06CE\u0648\u06CC\u0633\u062A\u06D5 \u0645\u06C6\u0628\u0627\u06CC\u0644\u06CE\u06A9\u06CC \u0632\u06CC\u0631\u06D5\u06A9\u06CC \u0628\u06CE\u06A9\u0627\u0631 \u0648 \u0645\u06C6\u0628\u0627\u06CC\u0644\u06CE\u06A9\u06CC \u062A\u0627\u06CC\u0628\u06D5\u062A \u0626\u0627\u0645\u0627\u062F\u06D5 \u0628\u06A9\u06D5\u06CC\u062A<span class='underline' title='Commonly known as: mobile phone number'>MSISDN</span>, \u0648 \u0628\u0627\u0631\u0648\u062F\u06C6\u062E\u06CC \u0633\u06CC\u06AF\u0646\u0627\u06B5\u06CC \u0628\u0627\u0634\u06CC\u0627\u0646 \u0647\u06D5\u0628\u06CE\u062A \u0628\u06C6 \u062F\u0627\u0646\u0627\u0646\u06CC \u062A\u06CE\u0631\u0645\u06CC\u0646\u0627\u06B5\u06CC \u067E\u0634\u062A\u0695\u0627\u0633\u062A\u06A9\u0631\u062F\u0646\u06D5\u0648\u06D5 \u0648 \u0626\u06D5\u0646\u062C\u0627\u0645\u062F\u0627\u0646\u06CC \u0626\u06D5\u0631\u06A9\u06D5\u06A9\u0627\u0646\u06CC \u062F\u06D5\u0633\u062A\u0695\u0627\u06AF\u06D5\u06CC\u0634\u062A\u0646 \u0628\u06D5 \u067E\u0634\u062A\u0695\u0627\u0633\u062A\u06A9\u0631\u062F\u0646\u06D5\u0648\u06D5 \u0644\u06D5 \u06A9\u0627\u062A\u06CC \u0695\u0627\u0633\u062A\u06D5\u0642\u06CC\u0646\u06D5\u062F\u0627.";
    faq21 = "FAQ";
    ledger21 = "Ledger";
    termsOfService21 = "\u0645\u06D5\u0631\u062C\u06D5\u06A9\u0627\u0646\u06CC \u062E\u0632\u0645\u06D5\u062A\u06AF\u0648\u0632\u0627\u0631\u06CC";
    privacy_policy21 = "\u0633\u06CC\u0627\u0633\u06D5\u062A\u06CC \u067E\u0627\u0631\u0627\u0633\u062A\u0646\u06CC \u0646\u0647\u06CE\u0646\u06CC";
